-- Schema for Domain: revenue | Business: Travel_Hospitality | Version: v2_mvm
-- Generated on: 2026-06-22 19:42:22

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `vibe_travel_hospitality_v1`.`revenue` COMMENT 'Authoritative source for pricing strategies, rate plans, yield optimization, and revenue performance. Manages BAR (Best Available Rate), dynamic pricing rules, DRR (Dynamic Rate Rules), rate restrictions, demand forecasting, and competitive benchmarking (STR STAR Report, RGI, MPI, ARI). Tracks ADR, RevPAR, TRevPAR, and GOPPAR metrics. Integrates with IDeaS G3 RMS and Infor EzRMS.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `vibe_travel_hospitality_v1`.`revenue`.`revenue_rate_plan` (
    `revenue_rate_plan_id` BIGINT COMMENT 'Unique surrogate identifier for each rate plan record in the revenue management system. Primary key for the revenue_rate_plan data product. Role: MASTER_RESOURCE.',
    `currency_id` BIGINT COMMENT 'Foreign key linking to property.currency. Business justification: Rate plan pricing requires a validated currency reference for multi-currency property operations. currency_code is a denormalized plain attribute; replacing with currency_id enforces 3NF and enables e',
    `channel_id` BIGINT COMMENT 'Foreign key linking to channel.channel. Business justification: Rate plans are distributed through specific channels (OTA, GDS, direct booking). Revenue managers configure which channels can sell which rate plans - core distribution strategy. Replaces denormalized',
    `franchise_agreement_id` BIGINT COMMENT 'Foreign key linking to property.franchise_agreement. Business justification: Franchise agreements mandate minimum rate floors, royalty fee structures, and GDS eligibility requirements that govern rate plan configuration. Linking revenue_rate_plan to franchise_agreement enables',
    `fnb_outlet_id` BIGINT COMMENT 'Foreign key linking to fnb.fnb_outlet. Business justification: Rate plans include F&B benefits (breakfast at specific outlet, dining credits). Required for package fulfillment, benefit tracking, revenue allocation between rooms and F&B departments per USALI stand',
    `menu_id` BIGINT COMMENT 'Foreign key linking to fnb.menu. Business justification: Rate plans reference specific menus for included meals (breakfast menu version, dinner package menu). Required for package rate construction, menu version control, guest entitlement verification at ou',
    `revenue_center_id` BIGINT COMMENT 'Foreign key linking to fnb.revenue_center. Business justification: Rate plans with F&B inclusions (resort credits, meal plans) are scoped to a specific revenue center (e.g., pool bar only, main restaurant only). revenue_rate_plan links to fnb_outlet and menu but not ',
    `tier_id` BIGINT COMMENT 'Foreign key linking to loyalty.tier. Business justification: Rate plans enforce tier-specific eligibility (loyalty_tier_required field exists). Business process: validating member tier qualification for rate plan access at booking time. Essential for tier-based',
    `market_segment_id` BIGINT COMMENT 'Foreign key linking to revenue.market_segment. Business justification: Revenue rate plans are designed for specific market segments — the market_segment_code on revenue_rate_plan is a denormalized reference to the market_segment master. Adding market_segment_id normalize',
    `meeting_space_id` BIGINT COMMENT 'Foreign key linking to property.meeting_space. Business justification: Meeting space rental rate plans are a distinct revenue management discipline. Linking revenue_rate_plan to meeting_space enables space-specific pricing (by capacity, AV equipment, rental tier), minimu',
    `promotion_id` BIGINT COMMENT 'Foreign key linking to loyalty.promotion. Business justification: Promotional rate plans (e.g., a Stay 3 Pay 2 rate plan tied to a loyalty bonus-points promotion) require a direct rate-plan-to-promotion link for correct points multiplier application, promotion eli',
    `property_id` BIGINT COMMENT 'Reference to the property or hotel at which this rate plan is applicable. Enables property-level rate plan management across a multi-property portfolio. A null value indicates a chain-wide or global rate plan applicable to all properties.',
    `room_type_id` BIGINT COMMENT 'Reference to the specific room type or room category to which this rate plan applies. A null value indicates the rate plan applies to all room types at the associated property.',
    `advance_purchase_days` STRING COMMENT 'Minimum number of days prior to arrival that a booking must be made to qualify for this rate plan. Common values are 7, 14, 21, or 30 days for advance purchase promotional rates. A value of 0 indicates no advance purchase requirement.',
    `approved_by` STRING COMMENT 'Name or identifier of the revenue manager or director who approved this rate plan for distribution. Supports SOX financial controls and internal audit requirements for rate authorization governance.',
    `approved_timestamp` TIMESTAMP COMMENT 'The timestamp when this rate plan was formally approved for activation and distribution. Distinct from created_timestamp; captures the authorization event in the rate plan lifecycle. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `base_rate_amount` DECIMAL(18,2) COMMENT 'The principal nightly room rate amount in the operating currency before any adjustments, taxes, or fees. Represents the rack rate or floor price for this rate plan. Used as the reference value for ADR (Average Daily Rate) and RevPAR (Revenue Per Available Room) calculations. Satisfies MASTER_RESOURCE MEASUREMENT_OR_VALUE category.',
    `booking_window_close_date` DATE COMMENT 'The last date on which new reservations can be made under this rate plan. After this date the rate plan is closed to new bookings even if the stay dates fall within the effective period.',
    `booking_window_open_date` DATE COMMENT 'The earliest date on which reservations can be made under this rate plan. Used to control promotional rate availability windows and prevent premature booking of seasonal or event-driven rates.',
    `cancellation_policy_code` STRING COMMENT 'Code referencing the cancellation and penalty policy associated with this rate plan (e.g., FLEX24H, NRR_NOREF, 48H_PENALTY). Determines guest refund eligibility and penalty charges upon cancellation. Critical for NRR (Non-Refundable Rate) and advance purchase rate plans.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `commission_pct` DECIMAL(18,2) COMMENT 'The percentage of the room rate payable as commission to the booking agent or OTA when is_commissionable is true. Expressed as a percentage (e.g., 10.00 for 10%). Null when is_commissionable is false.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this rate plan record was first created in the source system. Used for audit trail, data lineage, and compliance reporting. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `discount_pct` DECIMAL(18,2) COMMENT 'Percentage discount applied to the BAR (Best Available Rate) or rack rate to derive this rate plans selling price. Used for corporate negotiated rates, loyalty member rates, and promotional rates. A value of 0 indicates no discount from the reference rate.',
    `drr_eligible` BOOLEAN COMMENT 'Indicates whether this rate plan is subject to DRR (Dynamic Rate Rule) adjustments by the revenue management system. When true, IDeaS G3 RMS or Infor EzRMS may automatically adjust the rate based on demand forecasts, occupancy levels, and competitive benchmarking.',
    `effective_date` DATE COMMENT 'The calendar date from which this rate plan becomes active and bookable. Used by IDeaS G3 RMS and Sabre SynXis CRS to control rate availability windows. Satisfies MASTER_AGREEMENT EFFECTIVE_FROM category.',
    `expiry_date` DATE COMMENT 'The calendar date after which this rate plan is no longer available for new bookings. Null indicates an open-ended rate plan with no defined end date. Satisfies MASTER_AGREEMENT EFFECTIVE_UNTIL category.',
    `gds_eligible` BOOLEAN COMMENT 'Indicates whether this rate plan is distributed through GDS (Global Distribution System) channels such as Amadeus, Sabre, Travelport. Controls rate visibility to travel agents using GDS booking tools.',
    `is_commissionable` BOOLEAN COMMENT 'Indicates whether a travel agent or OTA (Online Travel Agency) commission is payable on bookings made under this rate plan. Drives commission accrual and payment processing in SAP S/4HANA AP.',
    `is_lra_eligible` BOOLEAN COMMENT 'Indicates whether this rate plan carries LRA (Last Room Availability) obligation, meaning the contracted rate must be honored even when only the last room in a category is available. Applicable to corporate negotiated rate contracts.',
    `is_refundable` BOOLEAN COMMENT 'Indicates whether bookings under this rate plan are eligible for a full refund upon cancellation within the policy window. False for NRR (Non-Refundable Rate) plans; true for flexible BAR (Best Available Rate) plans.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'The timestamp when this rate plan record was most recently updated in the source system. Used to detect changes for incremental ETL processing and audit compliance. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `loyalty_points_eligible` BOOLEAN COMMENT 'Indicates whether stays booked under this rate plan qualify for loyalty program points accrual. Wholesale, opaque, and certain promotional rates are typically ineligible for points earning.',
    `loyalty_tier_required` BOOLEAN COMMENT 'Minimum loyalty program membership tier required to access this rate plan. A value of none indicates the rate is open to all guests regardless of loyalty status. Used to gate exclusive member rates.',
    `max_los` STRING COMMENT 'Maximum number of nights permitted under this rate plan. Used to prevent extended stays at promotional or deeply discounted rates. A null value indicates no maximum stay restriction.',
    `meal_plan_type` STRING COMMENT 'Indicates the F&B (Food and Beverage) inclusions bundled with this rate plan. Room only includes no meals; bed and breakfast includes morning meal; half board includes breakfast and dinner; full board includes all three meals; all-inclusive covers meals, beverages, and selected activities.. Valid values are `room_only|bed_breakfast|half_board|full_board|all_inclusive`',
    `min_los` STRING COMMENT 'Minimum number of nights a guest must book to qualify for this rate plan. A LOS (Length of Stay) restriction used in yield optimization to drive longer stays during high-demand periods. A value of 1 indicates no minimum stay restriction.',
    `ota_eligible` BOOLEAN COMMENT 'Indicates whether this rate plan is distributed through OTA (Online Travel Agency) channels such as Booking.com, Expedia, or Agoda. Controls rate visibility on third-party booking platforms.',
    `rate_category` STRING COMMENT 'Secondary classification grouping rate plans by the market segment or distribution channel they serve. Public rates are available to all guests; negotiated rates are contracted with specific accounts; wholesale rates are sold through tour operators; group rates apply to block bookings; loyalty rates are exclusive to program members; employee rates are internal staff benefits.. Valid values are `public|negotiated|wholesale|group|loyalty|employee`',
    `rate_ceiling_amount` DECIMAL(18,2) COMMENT 'The maximum rate above which this rate plan cannot be sold, used to cap pricing during peak demand periods for contracted or promotional rates. Null indicates no ceiling constraint.',
    `rate_floor_amount` DECIMAL(18,2) COMMENT 'The minimum rate below which this rate plan cannot be sold, regardless of dynamic pricing adjustments. Protects rate integrity and brand positioning. Used by IDeaS G3 RMS as a hard constraint in yield optimization algorithms.',
    `rate_level` DECIMAL(18,2) COMMENT 'Indicates the organizational scope at which this rate plan is defined and managed. Property-level plans apply to a single hotel; brand-level plans apply across a brand portfolio; chain-level plans apply across the entire company; global plans may span international markets.',
    `rate_plan_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying the rate plan across systems (e.g., BAR, CORP001, PKG-SPA). Used as the business key in IDeaS G3 RMS, Sabre SynXis CRS, and Oracle OPERA PMS for rate plan lookup and distribution. Satisfies MASTER_RESOURCE BUSINESS_IDENTIFIER category.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `rate_plan_description` STRING COMMENT 'Free-text description of the rate plans terms, inclusions, and conditions as displayed to guests and booking agents. Includes details on what is included in the rate, any special conditions, and marketing messaging.',
    `rate_plan_name` STRING COMMENT 'Human-readable name of the rate plan displayed to guests and revenue managers (e.g., Best Available Rate, AAA Member Rate, Advance Purchase 21-Day). Satisfies MASTER_RESOURCE IDENTITY_LABEL category.',
    `rate_plan_type` STRING COMMENT 'Classification of the rate plan by its commercial structure. BAR (Best Available Rate) is the publicly available flexible rate; LRA (Last Room Availability) guarantees availability to contracted accounts; NRR (Non-Refundable Rate) carries no cancellation flexibility; corporate rates are negotiated with companies; package rates bundle room with ancillary services; promotional rates are time-limited offers. Satisfies MASTER_RESOURCE CLASSIFICATION_OR_TYPE category.. Valid values are `BAR|LRA|NRR|corporate|package|promotional`',
    `rate_status` STRING COMMENT 'Current lifecycle state of the rate plan. Active plans are available for booking; inactive plans are temporarily disabled; draft plans are under configuration; suspended plans are paused due to yield or compliance review; archived plans are retired and no longer bookable. Satisfies MASTER_RESOURCE LIFECYCLE_STATUS category.. Valid values are `active|inactive|draft|suspended|archived`',
    `source_system_code` STRING COMMENT 'Identifies the operational system of record from which this rate plan record was sourced. Enables data lineage tracking and conflict resolution when the same rate plan exists in multiple systems.. Valid values are `IDEASG3|SYNXIS|OPERA|EZRMS`',
    `source_system_rate_reference` DECIMAL(18,2) COMMENT 'The native identifier of this rate plan in the originating operational system (IDeaS G3 RMS, Sabre SynXis CRS, or Oracle OPERA PMS). Enables bidirectional traceability between the lakehouse Silver layer and the system of record.',
    `stay_date_restriction` STRING COMMENT 'Defines any day-of-week or date-specific restrictions on when stays under this rate plan are permitted. Weekday-only and weekend-only restrictions are common for corporate and leisure rates respectively; blackout dates exclude specific high-demand periods.. Valid values are `none|weekday_only|weekend_only|blackout_dates|specific_dates`',
    `tax_inclusive` BOOLEAN COMMENT 'Indicates whether the base_rate_amount includes applicable taxes (VAT, occupancy tax, city tax). True for tax-inclusive markets; false for markets where taxes are added at checkout. Critical for accurate revenue recognition under USALI and IFRS/GAAP.',
    CONSTRAINT pk_revenue_rate_plan PRIMARY KEY(`revenue_rate_plan_id`)
) COMMENT 'Master catalog of all rate plans available across properties, including BAR (Best Available Rate), LRA (Last Room Availability), NRR (Non-Refundable Rate), corporate negotiated rates, package rates, and promotional rates. Defines rate structure, cancellation policy, meal plan inclusions, booking conditions, and distribution eligibility. Sourced from IDeaS G3 RMS and Sabre SynXis CRS. This is the SSOT for rate plan definitions.';

CREATE OR REPLACE TABLE `vibe_travel_hospitality_v1`.`revenue`.`rate_restriction` (
    `rate_restriction_id` BIGINT COMMENT 'Unique surrogate identifier for each rate restriction record in the revenue management system. Primary key for the rate_restriction data product in the Databricks Silver Layer.',
    `cancellation_policy_id` BIGINT COMMENT 'Foreign key linking to reservation.cancellation_policy. Business justification: Revenue managers apply cancellation policy restrictions as part of yield management strategy. Rate restrictions must enforce specific cancellation terms (non-refundable, free cancellation windows) to ',
    `currency_id` BIGINT COMMENT 'Foreign key linking to property.currency. Business justification: Hurdle rate amounts on rate restrictions are currency-denominated; currency_code is a denormalized plain attribute. Linking to currency entity enables multi-currency revenue management and ensures hur',
    `channel_id` BIGINT COMMENT 'Foreign key linking to channel.channel. Business justification: Restrictions (stop-sell, min LOS, CTA/CTD) are applied per distribution channel. Revenue managers close channels selectively based on demand - essential inventory control operation. Enables channel-sp',
    `dynamic_rate_rule_id` BIGINT COMMENT 'Foreign key linking to revenue.dynamic_rate_rule. Business justification: Rate restrictions in IDeaS G3 RMS can be automatically triggered by Dynamic Rate Rules (DRRs) — the rms_recommendation_flag on rate_restriction indicates RMS-driven restrictions. Adding dynamic_rate_r',
    `market_segment_id` BIGINT COMMENT 'Foreign key linking to revenue.market_segment. Business justification: Rate restrictions can be scoped to market segments (e.g., restrict Leisure segment on peak dates). rate_restriction has market_segment_code (STRING) which should be normalized to FK. N rate_restrictio',
    `promotion_id` BIGINT COMMENT 'Foreign key linking to loyalty.promotion. Business justification: Loyalty promotions frequently grant restriction exemptions (e.g., a promotion waives minimum LOS for Platinum members). The existing is_loyalty_exempt flag is a denormalized boolean; replacing it with',
    `property_id` BIGINT COMMENT 'Reference to the property (hotel/resort) to which this rate restriction applies. Enables property-level yield optimization and restriction management across the portfolio.',
    `reservation_group_block_id` BIGINT COMMENT 'Reference to the group block associated with this restriction, when the restriction is applied to protect inventory for a specific group booking or MICE event. Null for transient/individual restrictions.',
    `revenue_rate_plan_id` BIGINT COMMENT 'Reference to the rate plan to which this restriction applies. Links to the rate plan master in the CRS/RMS (e.g., BAR, LRA, NRR, DRR). A restriction may apply to one or multiple rate plans; this field captures the primary rate plan association.',
    `room_type_id` BIGINT COMMENT 'Reference to the specific room type to which this restriction applies. When null, the restriction applies to all room types under the associated rate plan. Enables granular inventory control by room category.',
    `seasonal_calendar_id` BIGINT COMMENT 'Foreign key linking to property.seasonal_calendar. Business justification: rate_restriction has a plain season_code attribute — a direct denormalization of seasonal_calendar. Rate restrictions (CTA, CTD, min/max LOS) are operationally defined by season. FK to seasonal_cale',
    `advance_purchase_days` STRING COMMENT 'Minimum number of days prior to arrival that a booking must be made to qualify for this rate plan. Supports NRR (Non-Refundable Rate) and advance purchase yield strategies. Null when restriction type is not ADVANCE_PURCHASE.',
    `applied_timestamp` TIMESTAMP COMMENT 'The date and time when this rate restriction was activated and distributed to connected channels (CRS, GDS, OTA). Represents the principal business event time — when the restriction became operationally effective in the distribution ecosystem. Formatted as yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `created_by_user` STRING COMMENT 'Username or employee identifier of the revenue manager or system process that created this rate restriction record. Supports SOX financial controls audit trail and accountability for yield management decisions.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this rate restriction record was first created in the source system. Used for audit trail, data lineage, and SLA compliance tracking. Formatted as yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `days_of_week_mask` BIGINT COMMENT '7-character binary string indicating which days of the week the restriction applies, ordered Monday through Sunday (e.g., 1111100 = Mon–Fri only, 0000011 = Sat–Sun only). Enables day-of-week yield strategies such as weekend minimum stay requirements.',
    `demand_forecast_level` DECIMAL(18,2) COMMENT 'Demand forecast classification at the time this restriction was created or last updated, as determined by the RMS (IDeaS G3 or Infor EzRMS). Provides context for why the restriction was applied and supports post-hoc yield strategy analysis.',
    `distribution_status` STRING COMMENT 'Indicates the current distribution state of this restriction across connected channels via Sabre SynXis CRS. pending = queued for distribution; distributed = successfully pushed to all channels; failed = distribution error; partial = distributed to some but not all channels.. Valid values are `pending|distributed|failed|partial`',
    `effective_date` DATE COMMENT 'The calendar date from which this rate restriction becomes active and enforceable. Corresponds to the stay date (not booking date) unless the restriction type is ADVANCE_PURCHASE. Formatted as yyyy-MM-dd per model conventions.',
    `expiry_date` DATE COMMENT 'The last calendar date on which this rate restriction is enforceable (inclusive). Null indicates an open-ended restriction with no defined end. Formatted as yyyy-MM-dd per model conventions.',
    `hurdle_rate_amount` DECIMAL(18,2) COMMENT 'Minimum acceptable rate (in the propertys base currency) below which a booking will be rejected for this rate plan on the restricted date(s). A key RMS yield control used to protect ADR during high-demand periods. Null when restriction type is not HURDLE_RATE.',
    `is_blackout` BOOLEAN COMMENT 'Indicates whether the effective date range is designated as a blackout period, during which the rate plan is completely closed to new bookings. Commonly applied during peak demand events, holidays, or sold-out periods.',
    `is_cta` BOOLEAN COMMENT 'Indicates whether arrivals are blocked on the effective date(s) for this rate plan and room type. When True, guests cannot check in on the restricted date, preventing short-stay bookings that fragment inventory during high-demand periods.',
    `is_ctd` BOOLEAN COMMENT 'Indicates whether departures are blocked on the effective date(s) for this rate plan and room type. When True, guests cannot check out on the restricted date, used to extend stays through high-demand nights and maximize occupancy continuity.',
    `last_distributed_timestamp` TIMESTAMP COMMENT 'The date and time when this restriction was last successfully distributed to external channels (OTA, GDS) via Sabre SynXis CRS. Used to monitor distribution latency and SLA compliance for rate parity management.',
    `max_advance_purchase_days` STRING COMMENT 'Maximum number of days prior to arrival within which a booking must be made to qualify for this rate plan. Defines the booking window ceiling for advance purchase restrictions, preventing bookings made too far in advance at promotional rates.',
    `max_los` STRING COMMENT 'Maximum number of nights a guest is permitted to stay under this rate plan on the restricted date(s). Used to prevent long-stay bookings at discounted rates during high-demand periods. Null when restriction type is not MAX_LOS.',
    `min_los` STRING COMMENT 'Minimum number of nights a guest must stay to be eligible to book under this rate plan on the restricted date(s). A core yield optimization lever in revenue management. Null when restriction type is not MIN_LOS.',
    `notes` STRING COMMENT 'Free-text field for additional operational notes or context provided by the revenue manager regarding this restriction. May include references to specific events, competitive intelligence, or strategy rationale not captured in structured fields.',
    `override_allowed` BOOLEAN COMMENT 'Indicates whether a revenue manager or front desk supervisor is permitted to manually override this restriction for individual bookings. When False, the restriction is hard-enforced and cannot be bypassed in the PMS or CRS.',
    `override_authorization_level` BIGINT COMMENT 'Minimum staff authorization level required to override this restriction when override_allowed is True. Ensures appropriate governance over yield control exceptions. Null when override_allowed is False.',
    `priority_rank` STRING COMMENT 'Numeric priority rank used to resolve conflicts when multiple restrictions apply to the same rate plan, room type, and date. Lower values indicate higher priority. Ensures deterministic restriction enforcement when overlapping rules exist in the RMS.',
    `restriction_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying this rate restriction rule as defined in IDeaS G3 RMS or Sabre SynXis CRS. Used for cross-system reconciliation and distribution to OTA and GDS channels.. Valid values are `^[A-Z0-9_-]{2,30}$`',
    `restriction_name` STRING COMMENT 'Human-readable name describing the rate restriction rule (e.g., Weekend Min 2-Night Stay, Holiday CTA Block). Used by revenue managers and front desk staff to identify restrictions in PMS and RMS interfaces.',
    `restriction_reason` STRING COMMENT 'Free-text or coded explanation for why this restriction was applied (e.g., Peak demand event, Holiday blackout, Group block protection, RMS auto-recommendation). Supports revenue strategy documentation and post-stay performance analysis.',
    `restriction_scope` STRING COMMENT 'Defines the level at which this restriction is applied: property = entire property; room_type = specific room category; rate_plan = specific rate plan only; channel = specific distribution channel (OTA, GDS, direct). Determines how broadly the restriction is enforced across inventory.. Valid values are `property|room_type|rate_plan|channel`',
    `restriction_status` STRING COMMENT 'Current lifecycle state of the rate restriction record. active = currently enforced; inactive = disabled but retained for history; pending = scheduled but not yet effective; expired = past end date; overridden = manually superseded by a revenue manager.. Valid values are `active|inactive|pending|expired|overridden`',
    `restriction_type` STRING COMMENT 'Classification of the restriction mechanism applied. MIN_LOS = Minimum Length of Stay; MAX_LOS = Maximum Length of Stay; CTA = Closed to Arrival; CTD = Closed to Departure; ADVANCE_PURCHASE = minimum days before arrival required to book; BLACKOUT = date fully closed to booking; HURDLE_RATE = minimum acceptable rate threshold. [ENUM-REF-CANDIDATE: MIN_LOS|MAX_LOS|CTA|CTD|ADVANCE_PURCHASE|BLACKOUT|HURDLE_RATE — promote to reference product]',
    `rms_recommendation_flag` BOOLEAN COMMENT 'Indicates whether this restriction was system-recommended by the RMS (True) or manually created by a revenue manager (False). Enables analysis of RMS automation adoption rates and comparison of system vs. human yield decisions.',
    `source_system_restriction_reference` STRING COMMENT 'The native identifier of this restriction record in the originating operational system (IDeaS G3 RMS, Sabre SynXis CRS, etc.). Enables traceability and reconciliation between the lakehouse Silver Layer and the system of record.',
    `updated_by_user` STRING COMMENT 'Username or employee identifier of the revenue manager or system process that last modified this rate restriction record. Supports audit trail and governance of yield management changes.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this rate restriction record was last modified in the source system. Tracks the most recent change for audit and reconciliation purposes. Formatted as yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    CONSTRAINT pk_rate_restriction PRIMARY KEY(`rate_restriction_id`)
) COMMENT 'Operational records of rate restrictions applied to rate plans and room types, including minimum LOS (Length of Stay), maximum LOS, closed-to-arrival (CTA), closed-to-departure (CTD), advance purchase requirements, and blackout dates. Managed in IDeaS G3 RMS and distributed via Sabre SynXis CRS. Drives yield optimization by controlling which rates are bookable under specific conditions.';

CREATE OR REPLACE TABLE `vibe_travel_hospitality_v1`.`revenue`.`dynamic_rate_rule` (
    `dynamic_rate_rule_id` BIGINT COMMENT 'Unique surrogate identifier for a Dynamic Rate Rule (DRR) record in the revenue management system. Primary key for this entity.',
    `currency_id` BIGINT COMMENT 'Foreign key linking to property.currency. Business justification: Dynamic rate rule ceiling/floor amounts (max_rate_ceiling, min_rate_floor) are currency-denominated. currency_code is denormalized; FK to currency entity enforces 3NF and supports multi-currency RMS r',
    `demand_forecast_id` BIGINT COMMENT 'Identifier of the demand forecast record from IDeaS G3 RMS or Infor EzRMS that this forecast-based Dynamic Rate Rule references for its trigger evaluation.',
    `channel_id` BIGINT COMMENT 'Foreign key linking to channel.channel. Business justification: Dynamic pricing rules target specific channels differently (e.g., OTA rates adjust based on commission costs, direct channel gets best rate). RMS systems apply channel-specific rate optimization strat',
    `event_booking_id` BIGINT COMMENT 'Identifier of the local demand event (e.g., MICE event, conference, festival, sporting event) that triggers this event-based Dynamic Rate Rule. Links to the event master record in Delphi by Amadeus or the events domain.',
    `segment_id` BIGINT COMMENT 'Foreign key linking to guest.segment. Business justification: Dynamic pricing rules target specific guest segments for personalized rate adjustments. Revenue management systems apply segment-specific pricing logic (e.g., loyalty tier discounts, corporate negotia',
    `tier_id` BIGINT COMMENT 'Foreign key linking to loyalty.tier. Business justification: Dynamic pricing rules adjust rates based on member tier for personalized revenue optimization. Business process: applying tier-specific rate adjustments in revenue management systems to reward high-va',
    `market_segment_id` BIGINT COMMENT 'Foreign key linking to revenue.market_segment. Business justification: Dynamic rate rules can be scoped to specific market segments. dynamic_rate_rule has market_segment_code (STRING) which should be normalized to FK. N DRR records → 1 market_segment. Removes redundant m',
    `promotion_id` BIGINT COMMENT 'Foreign key linking to loyalty.promotion. Business justification: Loyalty promotions can trigger dynamic pricing rules (e.g., a flash-sale promotion activates a dynamic rate adjustment for eligible members). This FK enables promotion-triggered dynamic pricing workfl',
    `property_id` BIGINT COMMENT 'Identifier of the hotel or resort property to which this Dynamic Rate Rule applies. Links to the property master record in Oracle OPERA PMS.',
    `revenue_rate_plan_id` BIGINT COMMENT 'Identifier of the rate plan (e.g., BAR, LRA, NRR) to which this Dynamic Rate Rule applies. A null value indicates the rule applies across all eligible rate plans for the property.',
    `room_type_id` BIGINT COMMENT 'Identifier of the specific room type (e.g., standard king, deluxe suite) to which this Dynamic Rate Rule applies. A null value indicates the rule applies across all room types at the property.',
    `member_id` BIGINT COMMENT 'Foreign key linking to loyalty.member. Business justification: Dynamic rules can target specific high-value members for personalized pricing strategies. Business process: VIP member-specific rate rules for retention and revenue optimization, common in luxury hosp',
    `adjustment_direction` STRING COMMENT 'Indicates whether the Dynamic Rate Rule increases or decreases the rate when triggered. Provides explicit directional intent separate from the sign of adjustment_value to prevent ambiguity in RMS configuration.. Valid values are `increase|decrease`',
    `adjustment_type` STRING COMMENT 'Method by which the Dynamic Rate Rule adjusts the published rate when triggered. Percentage applies a relative increase or decrease to the current rate; absolute_amount adds or subtracts a fixed currency value; bar_offset moves the rate a fixed amount above or below the Best Available Rate (BAR); bar_multiplier applies a multiplier to the BAR.. Valid values are `percentage|absolute_amount|bar_offset|bar_multiplier`',
    `adjustment_value` DECIMAL(18,2) COMMENT 'The magnitude of the rate adjustment applied when the Dynamic Rate Rule is triggered. Interpreted according to adjustment_type: a value of 0.10 with type percentage means a 10% rate increase; a value of 25.00 with type absolute_amount means a $25 rate increase; a value of -15.00 with type bar_offset means $15 below BAR.',
    `advance_booking_max_days` STRING COMMENT 'Maximum number of days in advance of the arrival date within which a booking must be made for this Dynamic Rate Rule to be eligible to apply. Null indicates no upper advance booking restriction.',
    `advance_booking_min_days` STRING COMMENT 'Minimum number of days in advance of the arrival date that a booking must be made for this Dynamic Rate Rule to be eligible to apply. Supports advance purchase pricing strategies.',
    `approval_status` STRING COMMENT 'Workflow approval state of the Dynamic Rate Rule indicating whether it has been reviewed and authorized by a revenue manager before activation. Supports SOX-compliant pricing governance controls.. Valid values are `pending_approval|approved|rejected|auto_approved`',
    `approved_by` STRING COMMENT 'Name or employee identifier of the revenue manager or director who approved this Dynamic Rate Rule for activation. Required for SOX financial controls audit trail on pricing decisions.',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when this Dynamic Rate Rule was approved for activation by the authorized revenue manager. Part of the pricing governance audit trail required under SOX financial controls.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this Dynamic Rate Rule record was first created in the system. Part of the standard audit trail for pricing configuration governance.',
    `days_of_week_mask` BIGINT COMMENT 'Seven-character binary string (positions 1–7 = Mon–Sun) indicating which days of the week this Dynamic Rate Rule is eligible to fire. A value of 1111100 means Monday through Friday only. Enables day-of-week yield optimization strategies.',
    `effective_from` DATE COMMENT 'The calendar date from which this Dynamic Rate Rule becomes active and eligible to trigger automated pricing adjustments in the RMS. Aligns with the stay date range for yield optimization.',
    `effective_until` DATE COMMENT 'The calendar date on which this Dynamic Rate Rule expires and ceases to trigger automated pricing adjustments. Null indicates an open-ended rule with no defined expiry.',
    `is_stackable` BOOLEAN COMMENT 'Indicates whether this Dynamic Rate Rule can be combined (stacked) with other active rules for the same stay date, room type, and rate plan. When False, this rule takes exclusive precedence based on rule_priority and no other rules are applied concurrently.',
    `last_triggered_timestamp` TIMESTAMP COMMENT 'Date and time when this Dynamic Rate Rule was most recently evaluated as true and triggered an automated pricing adjustment in the RMS. Used by revenue managers to monitor rule activity and effectiveness.',
    `los_max_nights` STRING COMMENT 'Maximum Length of Stay (LOS) restriction in nights beyond which this Dynamic Rate Rule does not apply. Null indicates no upper LOS restriction.',
    `los_min_nights` STRING COMMENT 'Minimum Length of Stay (LOS) restriction in nights that must be satisfied for this Dynamic Rate Rule to apply. Used in LOS-based yield optimization to drive longer stays during high-demand periods.',
    `max_rate_ceiling` DECIMAL(18,2) COMMENT 'The highest permissible rate (in property currency) that this Dynamic Rate Rule may produce after adjustment. Acts as a pricing guardrail to prevent rates from exceeding the propertys maximum acceptable rate cap. Sensitive pricing strategy data.',
    `min_rate_floor` DECIMAL(18,2) COMMENT 'The lowest permissible rate (in property currency) that this Dynamic Rate Rule may produce after adjustment. Acts as a pricing guardrail to prevent rates from falling below the propertys minimum acceptable ADR threshold. Sensitive pricing strategy data.',
    `pickup_window_days` STRING COMMENT 'Number of days in the booking pickup window used to evaluate pickup velocity for pickup-based Dynamic Rate Rules. For example, a value of 7 means the rule evaluates rooms booked in the last 7 days.',
    `rms_rule_reference_code` STRING COMMENT 'Native rule identifier assigned by the source Revenue Management System (IDeaS G3 RMS or Infor EzRMS) for this Dynamic Rate Rule. Used for system-of-record traceability and reconciliation between the lakehouse Silver layer and the operational RMS.',
    `rule_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying the Dynamic Rate Rule within the Revenue Management System (RMS). Used for cross-system reference between IDeaS G3 RMS, Infor EzRMS, and Sabre SynXis CRS.. Valid values are `^[A-Z0-9_-]{2,30}$`',
    `rule_description` STRING COMMENT 'Detailed narrative description of the Dynamic Rate Rules business purpose, pricing logic, and intended yield optimization outcome.',
    `rule_name` STRING COMMENT 'Human-readable name describing the Dynamic Rate Rule, used by revenue managers to identify and manage pricing strategies within the RMS dashboard.',
    `rule_priority` STRING COMMENT 'Numeric priority ranking that determines the order of evaluation when multiple Dynamic Rate Rules are eligible to fire simultaneously for the same property, room type, and rate plan. Lower numeric values indicate higher priority (e.g., 1 = highest priority).',
    `rule_status` STRING COMMENT 'Current lifecycle state of the Dynamic Rate Rule governing whether it is eligible to trigger automated pricing adjustments. Active rules are evaluated by the RMS engine; draft rules are under configuration; suspended rules are temporarily disabled; archived rules are retained for historical audit.. Valid values are `active|inactive|draft|suspended|archived`',
    `rule_type` STRING COMMENT 'Classification of the Dynamic Rate Rule by the trigger mechanism driving automated pricing adjustments. Occupancy-based rules fire on OCC thresholds; pickup-based on booking velocity; competitive-based on RGI/ARI/MPI benchmarks from STR STAR Report; event-based on MICE or local demand events; LOS-based on Length of Stay (LOS) restrictions; forecast-based on RMS demand forecasts. [ENUM-REF-CANDIDATE: occupancy_based|pickup_based|competitive_based|event_based|los_based|forecast_based — promote to reference product]. Valid values are `occupancy_based|pickup_based|competitive_based|event_based|los_based|forecast_based`',
    `trigger_count` STRING COMMENT 'Cumulative number of times this Dynamic Rate Rule has been triggered and applied a pricing adjustment since its activation date. Used to assess rule utilization and yield optimization effectiveness.',
    `trigger_threshold_operator` STRING COMMENT 'Comparison operator applied to the trigger threshold value to determine whether the rule condition is met. For example, greater_than with a threshold of 0.80 means the rule fires when OCC exceeds 80%.. Valid values are `greater_than|less_than|greater_than_or_equal|less_than_or_equal|equal`',
    `trigger_threshold_unit` STRING COMMENT 'Unit of measure for the trigger threshold value. Percentage applies to OCC-based rules; room_count applies to pickup-based rules; index_value applies to competitive benchmarking rules (RGI, MPI, ARI); currency_amount applies to ADR-based triggers; nights applies to LOS-based rules.. Valid values are `percentage|room_count|index_value|currency_amount|nights`',
    `trigger_threshold_value` DECIMAL(18,2) COMMENT 'The numeric threshold at which this Dynamic Rate Rule fires. For occupancy-based rules, this is the OCC percentage (e.g., 0.80 = 80%). For pickup-based rules, this is the number of rooms picked up within the pickup window. For competitive-based rules, this is the RGI or ARI index value.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this Dynamic Rate Rule record was most recently modified. Used for change data capture (CDC) in the Databricks Lakehouse Silver layer ETL pipeline.',
    `version_number` STRING COMMENT 'Incremental version counter tracking the number of times this Dynamic Rate Rule configuration has been modified. Supports audit trail and change management for pricing strategy governance.',
    CONSTRAINT pk_dynamic_rate_rule PRIMARY KEY(`dynamic_rate_rule_id`)
) COMMENT 'DRR (Dynamic Rate Rule) definitions governing automated pricing adjustments in IDeaS G3 RMS and Infor EzRMS. Captures rule type (occupancy-based, pickup-based, competitive-based, event-based), trigger thresholds, adjustment type (percentage, absolute, BAR offset), applicable room types, applicable rate plans, effective date ranges, and rule priority. Core mechanism for yield optimization and dynamic pricing strategy.';

CREATE OR REPLACE TABLE `vibe_travel_hospitality_v1`.`revenue`.`rate_availability` (
    `rate_availability_id` BIGINT COMMENT 'Unique surrogate identifier for each daily rate and availability snapshot record in the Silver layer lakehouse. Primary key for the rate_availability data product.',
    `cancellation_policy_id` BIGINT COMMENT 'Foreign key linking to reservation.cancellation_policy. Business justification: Rate availability snapshots distributed to OTAs and GDS must include the specific cancellation policy for rate shopping compliance and guest transparency. Channel managers need this link to ensure acc',
    `channel_rate_plan_id` BIGINT COMMENT 'Foreign key linking to channel.channel_rate_plan. Business justification: Rate availability records govern which rates are open or closed per channel. Linking to the specific channel_rate_plan enables rate parity monitoring — a named compliance process — and allows revenue ',
    `currency_id` BIGINT COMMENT 'Foreign key linking to property.currency. Business justification: Rate availability records (bar_rate, rack_rate, min_rate, max_rate) are currency-denominated. currency_code is denormalized; FK to currency enforces 3NF and is required for GDS rate distribution parit',
    `demand_forecast_id` BIGINT COMMENT 'Foreign key linking to revenue.demand_forecast. Business justification: Rate availability snapshots in IDeaS G3 RMS are directly informed by demand forecasts — the occupancy forecast percentage and demand level drive BAR and availability decisions. Adding demand_forecast_',
    `channel_id` BIGINT COMMENT 'Foreign key linking to channel.channel. Business justification: Rate/availability snapshots are channel-specific - each channel sees different rates and inventory based on connectivity and contracts. Core distribution management requires tracking what each channel',
    `dynamic_rate_rule_id` BIGINT COMMENT 'Reference to the Dynamic Rate Rule (DRR) applied by IDeaS G3 RMS to derive the current BAR for this snapshot. DRRs define the algorithmic pricing logic (demand-based adjustments, day-of-week factors, lead-time curves) that drive dynamic pricing decisions.',
    `inventory_control_id` BIGINT COMMENT 'Foreign key linking to revenue.inventory_control. Business justification: Rate availability snapshots are the published output of inventory control decisions — the available_rooms, stop_sell, closed_to_arrival, and closed_to_departure values on rate_availability directly re',
    `property_id` BIGINT COMMENT 'Reference to the property (hotel, resort, or vacation property) for which this rate and availability snapshot applies. Sourced from Oracle OPERA PMS property configuration.',
    `room_type_id` BIGINT COMMENT 'Reference to the specific room type (e.g., King Deluxe, Double Standard, Suite) for which this rate and availability snapshot is captured. Sourced from Oracle OPERA PMS room type configuration.',
    `availability_status` STRING COMMENT 'Current open/closed availability status for this property, room type, rate plan, and date combination as managed in IDeaS G3 RMS and distributed via Sabre SynXis CRS. open = bookable; closed = inventory blocked; stop_sell = yield-driven closure; on_request = requires manual confirmation; min_stay_restriction = LOS restriction active; closed_to_arrival = no new arrivals permitted on this date.. Valid values are `open|closed|on_request|stop_sell|min_stay_restriction|closed_to_arrival`',
    `available_rooms` STRING COMMENT 'Number of rooms of this room type available for sale on the snapshot date at this property. Represents net sellable inventory after deducting out-of-order, out-of-service, and already-committed rooms. Core input for OCC (Occupancy Rate) and RevPAR calculations.',
    `bar_rate` DECIMAL(18,2) COMMENT 'The Best Available Rate (BAR) for this room type, property, and stay date — the lowest publicly available non-restricted rate as determined by IDeaS G3 RMS dynamic pricing engine. BAR is the anchor rate from which other rate plans are derived and is the primary rate distributed via Sabre SynXis CRS and OTA channels.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this rate and availability snapshot record was first created in the Silver layer lakehouse. Serves as the audit creation timestamp for data lineage and ETL pipeline tracking.',
    `effective_from_timestamp` TIMESTAMP COMMENT 'The date and time from which this rate and availability record became active and was distributed to booking channels. Used for bi-temporal modeling of rate history and supports point-in-time rate reconstruction for revenue audits and dispute resolution.',
    `effective_until_timestamp` TIMESTAMP COMMENT 'The date and time until which this rate and availability record remains active. Null indicates the record is currently active. Used for bi-temporal modeling and historical rate reconstruction. When a new rate update is received, the prior records effective_until_timestamp is set to the new records effective_from_timestamp.',
    `gds_rate_code` DECIMAL(18,2) COMMENT 'The rate code as published on GDS (Global Distribution System) platforms (Sabre, Amadeus, Travelport) via Sabre SynXis CRS. GDS rate codes follow standardized formats required for travel agent booking systems and corporate travel management programs.',
    `group_block_rooms` STRING COMMENT 'Number of rooms on the snapshot date allocated to group blocks (MICE, corporate groups, tour operators) as managed in Oracle OPERA PMS and Delphi by Amadeus. Group block inventory is excluded from transient availability and tracked separately for yield optimization.',
    `is_package_rate` DECIMAL(18,2) COMMENT 'Indicates whether this rate plan includes bundled package components (e.g., breakfast, spa credit, parking, airport transfer) beyond the base room charge. Package rates require component-level revenue allocation across USALI departments in Oracle OPERA PMS.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The date and time when this rate and availability record was last modified in the source system (IDeaS G3 RMS or Sabre SynXis CRS). Represents the business event timestamp of the most recent pricing or availability change. Critical for real-time channel distribution synchronization and SLA monitoring.',
    `max_rate` DECIMAL(18,2) COMMENT 'The ceiling rate (maximum sellable rate) for this room type, property, rate plan, and stay date as configured in IDeaS G3 RMS. Caps pricing during peak demand periods to maintain guest trust and brand integrity, and supports rate parity compliance across channels.',
    `meal_plan_code` STRING COMMENT 'Code indicating the meal plan inclusion for this rate plan (RO = Room Only; BB = Bed and Breakfast; HB = Half Board; FB = Full Board; AI = All Inclusive). Affects rate composition, F&B revenue allocation, and package pricing in Oracle OPERA PMS and MICROS POS.. Valid values are `RO|BB|HB|FB|AI`',
    `min_rate` DECIMAL(18,2) COMMENT 'The floor rate (minimum sellable rate) for this room type, property, rate plan, and stay date as configured in IDeaS G3 RMS. Represents the lowest price at which the room may be sold under any circumstance, enforcing revenue floor controls and preventing rate erosion.',
    `occupancy_forecast_pct` DECIMAL(18,2) COMMENT 'Forecasted occupancy rate (OCC%) for the property on the snapshot date as projected by IDeaS G3 RMS or Infor EzRMS at the time of this snapshot. Expressed as a percentage (0.00–100.00). Used to validate pricing decisions and benchmark against STR STAR Report actuals.',
    `ota_rate_code` DECIMAL(18,2) COMMENT 'The rate identifier as assigned by the primary OTA (Online Travel Agency) partner (e.g., Expedia, Booking.com) for this rate plan and property combination. Used for rate parity monitoring, OTA reconciliation, and channel performance reporting.',
    `out_of_order_rooms` STRING COMMENT 'Number of rooms of this room type that are out of order (OOO) on the snapshot date due to maintenance, renovation, or damage. Out-of-order rooms are excluded from sellable inventory and impact OCC denominator calculations per USALI standards.',
    `pickup_rooms` STRING COMMENT 'Number of rooms booked (picked up) for the snapshot date since the previous snapshot capture. Pickup velocity is a key revenue management signal used in IDeaS G3 RMS and Infor EzRMS to detect demand acceleration and trigger dynamic rate adjustments.',
    `pricing_override_flag` BOOLEAN COMMENT 'Indicates whether the current rate for this snapshot was manually overridden by a revenue manager, superseding the automated recommendation from IDeaS G3 RMS or Infor EzRMS. Manual overrides are tracked for revenue strategy audit and RMS model calibration.',
    `pricing_override_reason` STRING COMMENT 'Free-text or coded reason provided by the revenue manager when manually overriding the RMS-recommended rate. Populated only when pricing_override_flag is True. Used for revenue strategy review, RMS model improvement, and audit trail compliance.',
    `rack_rate` DECIMAL(18,2) COMMENT 'The published full undiscounted rate (rack rate) for this room type and stay date. Serves as the reference rate for discount calculations, loyalty redemption valuations, and walk-in pricing. Typically the highest rate tier and the baseline for USALI revenue reporting.',
    `rate_parity_flag` BOOLEAN COMMENT 'Indicates whether this rate record is subject to rate parity obligations with OTA (Online Travel Agency) partners. When True, the rate must match or be lower than rates published on OTA channels. Critical for OTA contract compliance and channel distribution management.',
    `rate_plan_code` STRING COMMENT 'Alphanumeric code identifying the rate plan as distributed via Sabre SynXis CRS and IDeaS G3 RMS (e.g., BAR, CORP01, PKG_BB, NRR_ADV21). Used for channel distribution, GDS mapping, and OTA rate loading.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `rate_plan_type` STRING COMMENT 'Classification of the rate plan governing this availability record. Determines pricing logic, cancellation policy, and channel eligibility. BAR (Best Available Rate) = dynamic public rate; LRA (Last Room Availability) = guaranteed availability; NRR (Non-Refundable Rate) = prepaid non-cancellable; corporate = negotiated account rate; package = bundled inclusions; group = block rate; loyalty = member rate; promotional = limited-time offer; wholesale = OTA/tour operator net rate. [ENUM-REF-CANDIDATE: bar|lra|nrr|corporate|package|group|loyalty|promotional|wholesale — promote to reference product]',
    `record_status` STRING COMMENT '',
    `revenue_management_system` DECIMAL(18,2) COMMENT 'Identifies the Revenue Management System (RMS) that generated or last updated the pricing recommendation for this snapshot record. Supports data lineage tracking and system-of-record attribution for audit and reconciliation purposes.',
    `snapshot_date` DATE COMMENT 'The stay date (arrival night) for which this rate and availability record applies. Represents the business event date — the night a guest would occupy the room at the stated rate. Core dimension for RevPAR and ADR reporting.',
    `source_system_record_reference` STRING COMMENT 'The native record identifier from the originating source system (IDeaS G3 RMS or Sabre SynXis CRS) for this rate and availability record. Enables traceability back to the system of record for reconciliation, reprocessing, and audit purposes.',
    `stop_sell` BOOLEAN COMMENT 'Indicates whether this room type and rate plan combination has been closed to all new bookings on the snapshot date regardless of available inventory. A hard yield management control applied in IDeaS G3 RMS to protect inventory for higher-value bookings or group blocks.',
    `total_rooms` STRING COMMENT 'Total physical room count for this room type at the property on the snapshot date. Used as the denominator for occupancy rate (OCC) and RevPAR calculations. Reflects the propertys sellable capacity before any restrictions.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp indicating when the record was last updated',
    CONSTRAINT pk_rate_availability PRIMARY KEY(`rate_availability_id`)
) COMMENT 'Daily rate and availability snapshot per property, room type, and rate plan combination as managed in IDeaS G3 RMS and distributed via Sabre SynXis CRS. Captures open/closed status, available inventory count, current BAR, minimum and maximum rates, and last-updated timestamp. Represents the real-time pricing grid used for reservation fulfillment and channel distribution.';

CREATE OR REPLACE TABLE `vibe_travel_hospitality_v1`.`revenue`.`demand_forecast` (
    `demand_forecast_id` BIGINT COMMENT 'Unique surrogate identifier for each demand forecast record generated by IDeaS G3 RMS or Infor EzRMS. Primary key for the demand_forecast data product in the Databricks Silver Layer.',
    `currency_id` BIGINT COMMENT 'Foreign key linking to property.currency. Business justification: Projected ADR, RevPAR, and room revenue in demand_forecast are currency-denominated. currency_code is denormalized; FK to currency enforces 3NF and enables accurate multi-currency forecast consolidati',
    `event_booking_id` BIGINT COMMENT 'Foreign key linking to event.event_booking. Business justification: Demand forecasts incorporate known definite event bookings as constrained demand drivers. Critical for pickup forecasting, unconstrained vs constrained demand modeling, and event impact analysis in re',
    `revenue_center_id` BIGINT COMMENT 'Foreign key linking to fnb.revenue_center. Business justification: Revenue center-level F&B demand forecasting (covers, revenue, labor hours by bar/restaurant/banquet) is a standard hotel operations process for staffing and procurement planning. demand_forecast links',
    `market_segment_id` BIGINT COMMENT 'Reference to the market segment (e.g., Transient, Group, Corporate, Leisure, OTA) for which the demand forecast is generated. Null when the forecast is at the property or room-type level only.',
    `promotion_id` BIGINT COMMENT 'Foreign key linking to loyalty.promotion. Business justification: Demand forecasters explicitly adjust unconstrained demand upward when a loyalty promotion (e.g., bonus-points weekend) is active. Without this FK, the forecast model cannot programmatically identify w',
    `property_id` BIGINT COMMENT 'Reference to the hotel or resort property for which this demand forecast was generated. Aligns with the Oracle OPERA PMS property master.',
    `room_type_id` BIGINT COMMENT 'Reference to the specific room type (e.g., King Deluxe, Double Standard, Suite) for which the demand forecast is generated. Null when the forecast is at the property or market-segment level only.',
    `seasonal_calendar_id` BIGINT COMMENT 'Foreign key linking to property.seasonal_calendar. Business justification: demand_forecast has is_holiday, is_special_event, special_event_name flags that duplicate seasonal_calendar data. Linking to seasonal_calendar enables RMS to automatically apply holiday/event demand u',
    `ari_forecast` DECIMAL(18,2) COMMENT 'Forecasted Average Rate Index (ARI), representing the propertys projected ADR relative to the competitive sets projected ADR. An ARI above 1.0 indicates the property is expected to achieve a rate premium over its competitive set.',
    `booking_pace_index` DECIMAL(18,2) COMMENT 'Ratio of current bookings on-hand for the forecast date compared to the same point in time in the prior year or baseline period. A value above 1.0 indicates ahead-of-pace demand; below 1.0 indicates behind-pace. Used by revenue managers to assess demand trajectory.',
    `confidence_interval_lower` DECIMAL(18,2) COMMENT 'Lower bound of the statistical confidence interval for the unconstrained demand forecast. Represents the pessimistic demand scenario used for risk-adjusted pricing and inventory control decisions in IDeaS G3 RMS.',
    `confidence_interval_upper` DECIMAL(18,2) COMMENT 'Upper bound of the statistical confidence interval for the unconstrained demand forecast. Represents the optimistic demand scenario used for overbooking strategy and group evaluation in IDeaS G3 RMS.',
    `confidence_level_pct` DECIMAL(18,2) COMMENT 'Statistical confidence level (e.g., 90.00, 95.00) associated with the forecast confidence interval. Indicates the probability that actual demand will fall within the lower and upper confidence bounds.',
    `constrained_demand` DECIMAL(18,2) COMMENT 'The forecasted room demand (in room-nights) after applying available inventory capacity constraints. Represents the demand the property can actually accommodate. Used for occupancy projection and revenue optimization.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this demand forecast record was first captured and written to the Silver Layer data product. Used for audit trail and data lineage tracking.',
    `day_of_week` BIGINT COMMENT 'Day of the week corresponding to the forecast date. Used for day-of-week demand pattern analysis, weekend vs. weekday segmentation, and pricing strategy differentiation. [ENUM-REF-CANDIDATE: Monday|Tuesday|Wednesday|Thursday|Friday|Saturday|Sunday — 7 candidates stripped; promote to reference product]',
    `demand_segment_mix_pct` DECIMAL(18,2) COMMENT 'Forecasted percentage share of total demand attributed to the specific market segment in this record. For example, if the Transient segment is expected to represent 65% of total demand on the forecast date, this field holds 65.00. Populated only for market-segment-level forecasts.',
    `forecast_accuracy_mape` DECIMAL(18,2) COMMENT 'Mean Absolute Percentage Error (MAPE) of the forecast model for this property-segment-horizon combination, based on historical back-testing. Lower values indicate higher model accuracy. Used to weight forecast confidence and flag low-accuracy forecasts for revenue manager review.',
    `forecast_date` DATE COMMENT 'The stay date (arrival date) for which the demand forecast values apply. Represents the future date being predicted, formatted as yyyy-MM-dd.',
    `forecast_granularity` STRING COMMENT 'The dimensional level at which this forecast record is generated. property is the highest level; room_type_segment is the most granular, combining room type and market segment dimensions as supported by IDeaS G3 RMS.. Valid values are `property|room_type|market_segment|room_type_segment`',
    `forecast_horizon_days` STRING COMMENT 'Number of days from the forecast run date to the forecast date, representing how far into the future this forecast projects. For example, a forecast run on 2024-01-01 for a stay date of 2024-04-01 has a horizon of 90 days. Used to assess forecast accuracy by horizon bucket.',
    `forecast_model_type` STRING COMMENT 'Classification of the algorithmic approach used to generate the forecast. time_series uses historical booking patterns; regression uses demand drivers; machine_learning uses ML-based models; hybrid combines multiple approaches; manual_override indicates a revenue manager manually adjusted the system forecast.. Valid values are `time_series|regression|machine_learning|hybrid|manual_override`',
    `forecast_model_version` STRING COMMENT 'Version identifier of the demand forecasting model or algorithm used to generate this forecast record (e.g., IDeaS-G3-v8.2, EzRMS-v5.1). Enables model performance tracking, A/B comparison, and audit of forecast methodology changes.',
    `forecast_run_reference` STRING COMMENT 'Externally-known unique identifier assigned by the Revenue Management System (RMS) to the specific forecast generation run that produced this record. Enables traceability back to the originating RMS batch or on-demand run.',
    `forecast_run_timestamp` TIMESTAMP COMMENT 'The date and time when this forecast record was generated by the Revenue Management System. Represents the principal business event timestamp for this transaction, formatted as yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `forecast_status` STRING COMMENT 'Current lifecycle state of this forecast record. active indicates the current operative forecast; superseded indicates a newer run has replaced it; draft indicates a preliminary run not yet published to pricing decisions; published indicates the forecast has been released to the Revenue Management System for pricing action; archived indicates historical retention only.. Valid values are `active|superseded|draft|published|archived`',
    `forecast_type` STRING COMMENT 'Classification of the forecast methodology or purpose. unconstrained reflects true market demand without inventory limits; constrained reflects demand limited by available inventory; group_evaluation is used for group block assessment in IDeaS G3 RMS; pickup reflects incremental booking pace; budget reflects the annual budget forecast baseline.. Valid values are `unconstrained|constrained|group_evaluation|pickup|budget`',
    `is_holiday` BOOLEAN COMMENT 'Flag indicating whether the forecast date falls on a public or national holiday in the propertys market. Used to apply holiday demand adjustment factors in the forecasting model.',
    `is_override` BOOLEAN COMMENT 'Flag indicating whether a revenue manager manually overrode the system-generated forecast values for this record. When true, the forecast reflects human judgment rather than pure algorithmic output. Used to track override frequency and assess model trust.',
    `is_special_event` BOOLEAN COMMENT 'Flag indicating whether the forecast date coincides with a special event (e.g., conference, concert, sporting event, public holiday) that is expected to materially impact demand. When true, the forecast may incorporate event-specific demand uplift factors.',
    `mpi_forecast` DECIMAL(18,2) COMMENT 'Forecasted Market Penetration Index (MPI), representing the propertys projected occupancy share relative to the competitive sets projected occupancy. An MPI above 1.0 indicates the property is expected to capture more than its fair share of market demand.',
    `projected_adr` DECIMAL(18,2) COMMENT 'Forecasted Average Daily Rate (ADR) in the propertys local currency for the forecast date. Represents the expected average revenue per occupied room. Core revenue management KPI used to drive pricing strategy.',
    `projected_cancellations` DECIMAL(18,2) COMMENT 'Forecasted number of room-nights expected to cancel from the current on-books position before the forecast date. Used to calculate net demand and inform overbooking strategy.',
    `projected_no_shows` DECIMAL(18,2) COMMENT 'Forecasted number of room-nights expected to result in no-show arrivals on the forecast date. Used alongside cancellation forecasts to calibrate overbooking levels and protect revenue.',
    `projected_occupancy_pct` DECIMAL(18,2) COMMENT 'Forecasted occupancy rate expressed as a percentage of available rooms expected to be sold on the forecast date. Calculated as constrained demand divided by total available rooms. Key input to RevPAR and yield optimization decisions.',
    `projected_pickup` DECIMAL(18,2) COMMENT 'Forecasted incremental room-nights expected to be booked between the forecast run date and the forecast date. Represents the additional demand the RMS expects to materialize beyond rooms already on books.',
    `projected_revpar` DECIMAL(18,2) COMMENT 'Forecasted Revenue Per Available Room (RevPAR) in the propertys local currency for the forecast date. Derived as projected ADR multiplied by projected occupancy rate. Primary yield optimization metric used by Revenue Management.',
    `projected_room_revenue` DECIMAL(18,2) COMMENT 'Forecasted total room revenue in the propertys local currency for the forecast date. Calculated as projected rooms sold multiplied by projected ADR. Used for budget variance analysis and revenue strategy.',
    `projected_rooms_available` STRING COMMENT 'Forecasted number of rooms available for sale on the forecast date after accounting for out-of-order, out-of-service, and maintenance blocks. Denominator for occupancy and RevPAR calculations.',
    `projected_rooms_sold` STRING COMMENT 'Forecasted number of rooms expected to be sold (occupied) on the forecast date. Used for housekeeping scheduling, staffing planning, and inventory control decisions.',
    `record_status` STRING COMMENT '',
    `rgi_forecast` DECIMAL(18,2) COMMENT 'Forecasted Revenue Generation Index (RGI), representing the propertys projected RevPAR relative to the competitive sets projected RevPAR. An RGI above 1.0 indicates the property is expected to outperform its competitive set. Sourced from STR STAR Report benchmarking data integrated into Infor EzRMS.',
    `rooms_on_books` STRING COMMENT 'Number of rooms already confirmed (on books) for the forecast date at the time the forecast was generated. Represents the definite demand component; the RMS adds pickup forecast to arrive at total projected demand.',
    `special_event_name` STRING COMMENT 'Name or description of the special event influencing demand on the forecast date (e.g., Super Bowl LIX, New Year Eve, City Marathon). Populated only when is_special_event is true.',
    `unconstrained_demand` DECIMAL(18,2) COMMENT 'The total forecasted room demand (in room-nights) without any inventory capacity constraints applied. Represents true market demand as estimated by the RMS model. Used to identify demand compression and inform inventory control decisions.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this demand forecast record was last modified in the Silver Layer, such as when a revised forecast supersedes a prior run for the same forecast date and segment.',
    CONSTRAINT pk_demand_forecast PRIMARY KEY(`demand_forecast_id`)
) COMMENT 'Forward-looking demand forecast records generated by IDeaS G3 RMS and Infor EzRMS at the property, room type, and market segment level. Captures forecast date, forecast horizon, unconstrained demand, constrained demand, projected occupancy, projected ADR, projected RevPAR, forecast confidence interval, and forecast model version. Used to drive pricing decisions, inventory controls, and group evaluation.';

CREATE OR REPLACE TABLE `vibe_travel_hospitality_v1`.`revenue`.`inventory_control` (
    `inventory_control_id` BIGINT COMMENT 'Primary key for inventory_control',
    `currency_id` BIGINT COMMENT 'Foreign key linking to property.currency. Business justification: Inventory control hurdle rates and current BAR values are currency-denominated. currency_code is denormalized; FK to currency enforces 3NF and ensures correct currency context for sell-limit and overb',
    `demand_forecast_id` BIGINT COMMENT 'Foreign key linking to revenue.demand_forecast. Business justification: Inventory control records in IDeaS G3 RMS and Infor EzRMS are governed by demand forecasts — the hurdle rate, sell limit, and overbooking parameters are set based on forecasted demand. Adding demand_f',
    `channel_id` BIGINT COMMENT 'Foreign key linking to channel.channel. Business justification: Inventory controls (sell limits, hurdles, stop-sells) vary by channel. Revenue managers allocate inventory differently across direct, OTA, GDS channels based on profitability and strategy. Fundamental',
    `dynamic_rate_rule_id` BIGINT COMMENT 'Reference to the Dynamic Rate Rule (DRR) applied to derive the current_bar for this room type and stay date. Links to the pricing strategy configuration governing automated rate adjustments in IDeaS G3 RMS.',
    `event_booking_id` BIGINT COMMENT 'Foreign key linking to event.event_booking. Business justification: Inventory controls (sell limits, hurdle rates, overbooking caps) are adjusted based on event booking displacement analysis. Essential for inventory optimization around events and group block allocatio',
    `property_id` BIGINT COMMENT 'Reference to the property (hotel, resort, or vacation property) to which this inventory control record applies. Aligns with Oracle OPERA PMS property configuration and IDeaS G3 RMS property setup.',
    `revenue_rate_plan_id` BIGINT COMMENT 'Reference to the rate plan (e.g., BAR, LRA, NRR, corporate, package) associated with this inventory control record. Determines the pricing tier and restrictions applied to the available inventory.',
    `room_type_id` BIGINT COMMENT 'Reference to the specific room type (e.g., King Deluxe, Double Standard, Suite) for which this inventory control record is defined. Aligns with Oracle OPERA PMS room type configuration and IDeaS G3 RMS room class setup.',
    `allotment_rooms` STRING COMMENT 'Number of rooms of this room type on the stay date allocated to contracted allotments (OTA allotments, wholesale, tour operator contracts). Managed via Sabre SynXis CRS channel management and reduces the freely-sellable transient inventory.',
    `approval_authority` STRING COMMENT 'Designates the level of authority required to approve the overbooking level for this inventory control record. Ensures governance and accountability for overbooking decisions per property SOPs and SOX internal control requirements.. Valid values are `rms_automated|revenue_manager|director_of_revenue|general_manager`',
    `available_room_count` STRING COMMENT 'Real-time count of rooms available for sale for this property, room type, stay date, and rate plan combination at the time of last update. Reflects physical inventory minus confirmed reservations, group blocks, and out-of-order rooms. Distributed via Sabre SynXis CRS for reservation fulfillment.',
    `control_record_code` STRING COMMENT 'Externally-known alphanumeric business identifier for this inventory control record as referenced in IDeaS G3 RMS and Sabre SynXis CRS. Used for cross-system reconciliation and audit traceability.. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `control_status` STRING COMMENT 'Current lifecycle state of this inventory control record indicating whether the room type/rate plan combination is open for sale, closed, restricted, pending review, or subject to a manual override. This is the real-time availability state distributed via Sabre SynXis CRS.. Valid values are `open|closed|restricted|pending|override`',
    `control_type` STRING COMMENT 'Classifies the category of inventory control applied to this record. Determines how the control_value is interpreted and enforced by the Revenue Management System. [ENUM-REF-CANDIDATE: hurdle_rate|sell_limit|overbooking_level|los_restriction|cta_restriction|ctd_restriction|allotment|group_block — promote to reference product]. Valid values are `hurdle_rate|sell_limit|overbooking_level|los_restriction|cta_restriction|ctd_restriction`',
    `control_value` DECIMAL(18,2) COMMENT 'The operative value for this control record as applied by the Revenue Management System. Interpretation depends on control_type: for hurdle_rate it is the minimum acceptable rate in local currency; for sell_limit it is the maximum rooms to sell; for overbooking_level it is the number of rooms above physical capacity authorized to sell.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this inventory control record was first created in the source Revenue Management System (IDeaS G3 RMS or Infor EzRMS). Provides the audit trail creation anchor for data lineage and SOX compliance.',
    `current_bar` DECIMAL(18,2) COMMENT 'The current Best Available Rate (BAR) in local currency for this room type and stay date as published via Sabre SynXis CRS and channel distribution. Represents the lowest publicly available non-restricted rate and is the primary pricing signal for transient demand.',
    `effective_from_timestamp` TIMESTAMP COMMENT 'The date and time from which this inventory control records control_value and restrictions became operative in the Revenue Management System. Supports temporal validity tracking and historical rate/availability grid reconstruction.',
    `effective_until_timestamp` TIMESTAMP COMMENT 'The date and time at which this inventory control records control_value and restrictions ceased to be operative. Null for currently active records. Enables point-in-time historical analysis of the rate/availability grid.',
    `group_block_rooms` STRING COMMENT 'Number of rooms of this room type on the stay date allocated to group blocks (MICE, tour groups, corporate groups). Reduces the transient sell limit and is managed via Delphi by Amadeus group block management and IDeaS G3 RMS group evaluation.',
    `hurdle_rate` DECIMAL(18,2) COMMENT 'Minimum acceptable rate (in local currency) below which a reservation for this room type on the stay date should not be accepted, as determined by the Revenue Management System. Used in displacement analysis and group evaluation in IDeaS G3 RMS.',
    `is_closed_to_arrival` BOOLEAN COMMENT 'Indicates whether arrivals are blocked for this room type and rate plan on the stay date (Closed to Arrival / CTA restriction). When True, guests may not check in on this date but may stay through it as part of a longer booking.',
    `is_closed_to_departure` BOOLEAN COMMENT 'Indicates whether departures are blocked for this room type and rate plan on the stay date (Closed to Departure / CTD restriction). When True, guests may not check out on this date, requiring stays to extend beyond it.',
    `is_override` BOOLEAN COMMENT 'Indicates whether the applied control_value represents a manual override of the system_recommended_value. True when a revenue manager has manually intervened; False when the system recommendation was accepted as-is. Critical for RMS model performance auditing.',
    `last_distributed_timestamp` TIMESTAMP COMMENT 'The date and time when this inventory control records rate and availability state was last successfully distributed to Sabre SynXis CRS and downstream channels (OTA, GDS). Critical for SLA monitoring and channel distribution reconciliation.',
    `max_los` STRING COMMENT 'Maximum number of nights a guest may stay when booking this room type at this rate plan on the stay date. Used to prevent long-stay displacement of higher-value transient demand during peak periods.',
    `max_rate` DECIMAL(18,2) COMMENT 'The ceiling rate in local currency above which no rate plan for this room type and stay date may be sold. Used to enforce rate integrity, prevent rate gouging, and comply with local pricing regulations during high-demand periods.',
    `min_los` STRING COMMENT 'Minimum number of nights a guest must stay to be eligible to book this room type at this rate plan on the stay date. A Length of Stay (LOS) restriction used to optimize revenue during high-demand periods by requiring longer stays.',
    `min_rate` DECIMAL(18,2) COMMENT 'The absolute floor rate in local currency below which no rate plan for this room type and stay date may be sold, regardless of channel or negotiated agreement. Enforced as a hard constraint in the Revenue Management System and CRS.',
    `occupancy_on_books` DECIMAL(18,2) COMMENT 'Current confirmed occupancy rate (OCC) percentage for this room type on the stay date at the time of last update, calculated as confirmed reservations divided by physical_room_count. Key input to dynamic pricing and sell limit decisions in the Revenue Management System.',
    `out_of_order_rooms` STRING COMMENT 'Number of rooms of this room type on the stay date designated as out of order (OOO) due to maintenance, renovation, or FF&E replacement. These rooms are excluded from sellable inventory and occupancy calculations per USALI standards.',
    `overbooking_absolute_cap` STRING COMMENT 'Hard ceiling on the absolute number of rooms that may be overbooked above physical capacity for this room type on the stay date, regardless of the overbooking_pct calculation. Prevents excessive walk exposure during high-demand periods.',
    `overbooking_pct` DECIMAL(18,2) COMMENT 'Maximum authorized overbooking level expressed as a percentage above physical room capacity for this room type on the stay date. Defined in the overbooking policy and used by IDeaS G3 RMS to set the sell limit above physical_room_count.',
    `override_reason` STRING COMMENT 'Free-text or coded justification provided by the revenue manager when is_override is True. Documents the business rationale for deviating from the system recommendation (e.g., local event, competitive action, group displacement). Required for audit and RMS calibration.',
    `physical_room_count` STRING COMMENT 'Total number of physical rooms of this room type at the property, representing the hard capacity ceiling before overbooking allowances are applied. Used as the denominator for occupancy rate (OCC) calculations.',
    `rate_availability_source` STRING COMMENT 'Identifies the originating system or process that set the current rate and availability state for this control record. Supports data lineage, audit, and reconciliation between IDeaS G3 RMS, Sabre SynXis CRS, and Oracle OPERA PMS.. Valid values are `rms_automated|manual_override|channel_manager|pms_direct`',
    `record_status` STRING COMMENT '',
    `sell_limit` STRING COMMENT 'Maximum number of rooms authorized to be sold for this room type on the stay date, inclusive of overbooking allowance. Set by the Revenue Management System and may exceed physical_room_count when overbooking is authorized. Enforced at the CRS and PMS booking engine.',
    `stay_date` DATE COMMENT 'The specific calendar date (night of stay) for which this inventory control record applies. Represents the primary dimension of the rate/availability grid alongside property, room type, and rate plan.',
    `system_recommended_value` DECIMAL(18,2) COMMENT 'The value recommended by the Revenue Management System (IDeaS G3 RMS or Infor EzRMS) prior to any manual override. Enables comparison between algorithmic recommendation and the applied control_value for yield optimization analysis and RMS model performance tracking.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this inventory control record was most recently modified in the source system. Used for incremental ETL processing, change detection, and audit trail maintenance in the Databricks Silver Layer.',
    `walk_compensation_type` STRING COMMENT 'Type of compensation offered to a walked guest when the walk_policy requires compensation. Governs the financial and loyalty implications of overbooking execution and is tracked for Guest Recovery Rate (GRR) and CPOR reporting.. Valid values are `cash_equivalent|room_upgrade|loyalty_points|voucher|partner_hotel`',
    `walk_policy` STRING COMMENT 'Defines the operational procedure to follow when a guest with a confirmed reservation cannot be accommodated due to overbooking (a walk). Determines whether the guest is walked to a partner hotel, upgraded, or compensated per AHLA guest relocation standards.. Valid values are `walk_and_compensate|walk_to_partner|upgrade_first|deny_walk`',
    CONSTRAINT pk_inventory_control PRIMARY KEY(`inventory_control_id`)
) COMMENT 'Inventory control records managing the complete room availability and pricing grid as applied in IDeaS G3 RMS. Encompasses hurdle rates, sell limits, overbooking levels, room type allotments, group blocks, and the resulting daily rate availability state per property, room type, and rate plan combination. Captures control type, room type, stay date, control value, system-recommended value, override indicator, overbooking policy parameters (max overbooking percentage, absolute cap, walk policy, compensation type, partner hotel agreements, approval authority), and real-time availability state (open/closed status, available inventory count, current BAR, minimum/maximum rates, last-updated timestamp). This is the SSOT for all inventory control decisions, overbooking policy configuration, and the rate/availability grid distributed via Sabre SynXis CRS for reservation fulfillment and channel distribution.';

CREATE OR REPLACE TABLE `vibe_travel_hospitality_v1`.`revenue`.`performance_actuals` (
    `performance_actuals_id` BIGINT COMMENT 'Primary key for performance_actuals',
    `budget_id` BIGINT COMMENT 'Foreign key linking to revenue.revenue_budget. Business justification: Performance actuals carry denormalized budget targets (budget_adr, budget_occupancy_rate, budget_room_revenue, budget_total_revenue) for variance computation. Adding revenue_budget_id normalizes these',
    `currency_id` BIGINT COMMENT 'Foreign key linking to property.currency. Business justification: All performance_actuals monetary KPIs (ADR, RevPAR, GOP, EBITDA) are currency-denominated. currency_code is denormalized; FK to currency enforces 3NF and is required for STR benchmarking, owner report',
    `demand_forecast_id` BIGINT COMMENT 'Foreign key linking to revenue.demand_forecast. Business justification: Performance actuals are compared against demand forecasts for MAPE (forecast accuracy) and variance analysis — a core function of IDeaS G3 RMS and STR STAR reporting. Adding demand_forecast_id links e',
    `event_booking_id` BIGINT COMMENT 'Foreign key linking to event.event_booking. Business justification: Daily actuals track which room nights and revenue came from specific event bookings for segment reporting. Required for event contribution analysis, MICE segment performance reporting, and group vs tr',
    `franchise_agreement_id` BIGINT COMMENT 'Foreign key linking to property.franchise_agreement. Business justification: Franchise fee calculations (royalty, marketing, loyalty fees) are computed from performance actuals revenue figures. Linking performance_actuals to franchise_agreement enables automated franchise fee ',
    `hierarchy_id` BIGINT COMMENT 'Foreign key linking to property.hierarchy. Business justification: Performance actuals are reported and benchmarked at hierarchy node levels (brand, region, cluster) for executive dashboards and STR market reporting. Linking to hierarchy enables hierarchical KPI roll',
    `fnb_outlet_id` BIGINT COMMENT 'Foreign key linking to fnb.fnb_outlet. Business justification: Daily actuals track outlet-level F&B revenue for TRevPAR calculation and USALI reporting. Required for total property revenue reporting, GOP analysis, outlet performance attribution in consolidated fi',
    `promotion_id` BIGINT COMMENT 'Foreign key linking to loyalty.promotion. Business justification: Promotion ROI / lift analysis is a named loyalty reporting process: did the double-points weekend actually lift RevPAR? Linking performance_actuals to the active promotion enables incremental revenue ',
    `property_id` BIGINT COMMENT 'Reference to the property for which this daily revenue performance record is captured. Links to the property master entity in the Property domain.',
    `revenue_center_id` BIGINT COMMENT 'Foreign key linking to fnb.revenue_center. Business justification: USALI mandates F&B performance reporting by revenue center (restaurant, bar, banquet). performance_actuals tracks fb_revenue but has no revenue_center FK. This link enables department-level P&L report',
    `seasonal_calendar_id` BIGINT COMMENT 'Foreign key linking to property.seasonal_calendar. Business justification: Performance actuals must be contextualized by season for meaningful YoY variance analysis (prior_year_revpar exists as a plain attr). Linking to seasonal_calendar enables season-adjusted STR benchmark',
    `adr` DECIMAL(18,2) COMMENT 'Average Daily Rate in the propertys operating currency, calculated as total room revenue divided by rooms sold (excluding complimentary). Core KPI for STR STAR Report benchmarking, RGI, ARI, and MPI calculations.',
    `ancillary_revenue` DECIMAL(18,2) COMMENT 'Total ancillary revenue on the performance date from upsells, packages, resort fees, and add-on services not captured in departmental revenue lines. Supports total revenue and TRevPAR reporting.',
    `ari` DECIMAL(18,2) COMMENT 'Average Rate Index representing the propertys ADR performance relative to its competitive set, sourced from STR STAR Report. ARI > 1.0 indicates the property is achieving a rate premium over its comp set.',
    `channel_direct_rooms` STRING COMMENT 'Number of rooms sold through direct channels (brand website, call center, walk-in) on the performance date. Supports direct vs. indirect channel mix analysis and cost-of-acquisition reporting.',
    `channel_ota_rooms` STRING COMMENT 'Number of rooms sold through Online Travel Agency (OTA) channels (e.g., Expedia, Booking.com) on the performance date. Supports channel distribution mix analysis and OTA commission cost management.',
    `cpor` DECIMAL(18,2) COMMENT 'Cost Per Occupied Room on the performance date, calculated as total rooms department operating expenses divided by rooms sold. Measures operational efficiency of the rooms department per USALI.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this performance actual record was first created in the data lakehouse Silver layer. Supports audit trail and data lineage requirements.',
    `ebitda_contribution` DECIMAL(18,2) COMMENT 'Property-level EBITDA contribution on the performance date, representing operating earnings before interest, taxes, depreciation, and amortization. Used for ownership reporting, asset valuation, and management contract performance measurement.',
    `fb_revenue` DECIMAL(18,2) COMMENT 'Total Food and Beverage revenue generated on the performance date across all F&B outlets (restaurants, bars, banquets, in-room dining). Sourced from Oracle Hospitality MICROS POS and reconciled against SAP S/4HANA. Included in TRevPAR calculation per USALI.',
    `gop` DECIMAL(18,2) COMMENT 'Gross Operating Profit on the performance date, calculated as total operated department revenue minus total operated department expenses per USALI. Key profitability metric for ownership reporting and management contracts.',
    `goppar` DECIMAL(18,2) COMMENT 'Gross Operating Profit Per Available Room in the propertys operating currency, calculated as GOP divided by rooms available. Measures overall property profitability efficiency. Core KPI for ownership reporting and management fee calculations.',
    `is_reconciled` BOOLEAN COMMENT 'Indicates whether this daily performance actual record has been reconciled between Oracle OPERA PMS and SAP S/4HANA General Ledger. True = reconciled and approved for reporting; False = pending reconciliation. Supports financial close and SOX controls.',
    `miscellaneous_income` DECIMAL(18,2) COMMENT 'Total miscellaneous and rental income on the performance date including rentals, commissions, and other non-departmental income per USALI non-operating income classification.',
    `mpi` DECIMAL(18,2) COMMENT 'Market Penetration Index representing the propertys occupancy performance relative to its competitive set, sourced from STR STAR Report. MPI > 1.0 indicates the property is capturing more than its fair share of market occupancy.',
    `occupancy_rate` DECIMAL(18,2) COMMENT 'Daily occupancy rate expressed as a decimal (e.g., 0.8250 = 82.50%), calculated as rooms sold divided by rooms available. Core KPI for the STR STAR Report, DOR, and ownership reporting. Stored as a raw ratio; display layer applies percentage formatting.',
    `parking_revenue` DECIMAL(18,2) COMMENT 'Total parking revenue generated on the performance date from valet, self-park, and garage operations. Classified under other operated departments per USALI and included in TRevPAR.',
    `performance_date` DATE COMMENT 'The calendar date (business date) for which this revenue performance actual record applies. Represents the stay date or operating day used in the Daily Operations Report (DOR) and all KPI calculations.',
    `prior_year_revpar` DECIMAL(18,2) COMMENT 'RevPAR for the same calendar date in the prior year. Used for year-over-year (YOY) variance analysis in the DOR, STR STAR Report benchmarking, and ownership reporting.',
    `record_status` STRING COMMENT 'Lifecycle status of this performance actual record indicating whether figures are preliminary (intra-day), final (end-of-day close), adjusted (post-close correction), or closed (period-locked). Supports audit and reconciliation workflows.. Valid values are `draft|preliminary|final|adjusted|closed`',
    `revpar` DECIMAL(18,2) COMMENT 'Revenue Per Available Room in the propertys operating currency, calculated as ADR multiplied by occupancy rate (or total room revenue divided by rooms available). Primary rooms revenue KPI for ownership reporting, STR STAR Report, and RGI benchmarking.',
    `rgi` DECIMAL(18,2) COMMENT 'Revenue Generation Index representing the propertys RevPAR performance relative to its competitive set, sourced from STR STAR Report. RGI > 1.0 indicates the property is outperforming its comp set. Core competitive benchmarking KPI.',
    `rooms_available` STRING COMMENT 'Total number of rooms available for sale on the performance date after deducting out-of-order (OOO) and out-of-service (OOS) rooms. Denominator for Occupancy Rate (OCC) and RevPAR calculations per USALI and STR STAR Report standards.',
    `rooms_complimentary` STRING COMMENT 'Number of rooms occupied on a complimentary (no-charge) basis on the performance date. Tracked separately per USALI for accurate ADR and revenue reporting, as complimentary rooms are excluded from ADR calculation.',
    `rooms_out_of_order` STRING COMMENT 'Number of rooms designated as out-of-order (OOO) on the performance date due to maintenance, renovation, or damage. Excluded from rooms available per USALI inventory standards.',
    `rooms_sold` STRING COMMENT 'Total number of rooms occupied (sold) on the performance date, including complimentary rooms. Used to calculate Occupancy Rate (OCC) and Average Daily Rate (ADR) per USALI standards.',
    `segment_contract_rooms` STRING COMMENT 'Number of rooms sold under negotiated contract rates (airline crew, long-stay corporate contracts) on the performance date. Supports contract segment revenue analysis and channel mix reporting.',
    `segment_group_rooms` STRING COMMENT 'Number of rooms sold to group accounts (MICE, corporate groups, tour groups) on the performance date. Supports group vs. transient mix analysis and group revenue contribution reporting per USALI.',
    `segment_transient_rooms` STRING COMMENT 'Number of rooms sold to transient (individual/FIT) guests on the performance date. Supports segment-level revenue analysis and channel mix reporting per USALI market segmentation standards.',
    `source_system_code` STRING COMMENT 'Identifies the operational system of record from which this performance actual record was sourced or reconciled (e.g., Oracle OPERA PMS for rooms data, SAP S/4HANA for financial totals). Supports data lineage and reconciliation audits.. Valid values are `OPERA_PMS|SAP_S4HANA|IDEASS_G3|INFOR_EZRMS|MANUAL`',
    `spa_revenue` DECIMAL(18,2) COMMENT 'Total spa and wellness revenue generated on the performance date. Included in total property revenue and TRevPAR calculation per USALI other operated departments classification.',
    `total_property_revenue` DECIMAL(18,2) COMMENT 'Total gross revenue across all operated departments and income streams on the performance date (rooms + F&B + spa + parking + other operated departments + miscellaneous + ancillary). Denominator basis for TRevPAR. Reconciled against SAP S/4HANA GL per USALI.',
    `total_room_revenue` DECIMAL(18,2) COMMENT 'Total gross room revenue generated on the performance date across all rate plans and channels, before deductions. Sourced from Oracle OPERA PMS and reconciled against SAP S/4HANA GL. Numerator for ADR and RevPAR calculations per USALI.',
    `trevpar` DECIMAL(18,2) COMMENT 'Total Revenue Per Available Room in the propertys operating currency, calculated as total property revenue divided by rooms available. Measures total revenue productivity of the property beyond rooms. Core KPI for ownership and management reporting.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this performance actual record was last modified, including post-close adjustments or reconciliation corrections. Supports audit trail and change tracking.',
    CONSTRAINT pk_performance_actuals PRIMARY KEY(`performance_actuals_id`)
) COMMENT 'Daily revenue performance actuals at the property level capturing all revenue streams aligned to USALI departmental reporting. Includes room revenue metrics (ADR, OCC, RevPAR, rooms sold, rooms available, total room revenue) and total property revenue metrics (F&B revenue, spa revenue, parking, other operated departments, miscellaneous income, ancillary revenue, TRevPAR, GOPPAR, CPOR, GOP, EBITDA contribution). Sourced from Oracle OPERA PMS and SAP S/4HANA, reconciled against USALI standards. This is the single authoritative record for all daily revenue performance — both rooms and total revenue — used for the Daily Operations Report (DOR), ownership reporting, TRevPAR/GOPPAR calculation, and variance analysis against budget.';

CREATE OR REPLACE TABLE `vibe_travel_hospitality_v1`.`revenue`.`market_segment` (
    `market_segment_id` BIGINT COMMENT 'Unique surrogate identifier for the market segment record. Primary key for the market_segment data product in the revenue domain. Role classification: MASTER_RESOURCE — this entity represents a classification resource used across revenue, reservation, and channel domains.',
    `currency_id` BIGINT COMMENT 'Foreign key linking to property.currency. Business justification: Market segment commission rates and contribution margin tiers are currency-context-dependent. currency_code is denormalized; FK to currency enforces 3NF and supports multi-currency segment profitabili',
    `ada_accommodation_typical` BOOLEAN COMMENT 'Indicates whether guests in this market segment typically require ADA (Americans with Disabilities Act) accessible accommodations. Relevant for government, medical, and certain group segments. Informs room inventory allocation and accessibility compliance reporting.',
    `avg_lead_time_days` STRING COMMENT 'Average number of days between booking date and arrival date for this market segment. Key input for demand forecasting in IDeaS G3 RMS and Infor EzRMS. Segments with short lead times (e.g., OTA last-minute) require different yield strategies than long-lead corporate or group segments. Represents the MEASUREMENT_OR_VALUE for this resource.',
    `avg_length_of_stay_nights` DECIMAL(18,2) COMMENT 'Average number of nights guests in this segment stay per booking (ALOS — Average Length of Stay). Used in revenue management for LOS (Length of Stay) restriction optimization, demand forecasting, and RevPAR (Revenue Per Available Room) modeling in IDeaS G3 RMS.',
    `cancellation_propensity` DECIMAL(18,2) COMMENT 'Qualitative classification of the historical cancellation rate tendency for this market segment. Informs overbooking strategy, no-show reserve calculations, and revenue protection policies in IDeaS G3 RMS. High-propensity segments (e.g., OTA flexible rate) require higher overbooking buffers.',
    `channel_affinity` STRING COMMENT 'Primary distribution channel through which this market segment predominantly books. Drives channel strategy, OTA (Online Travel Agency) commission management, and GDS (Global Distribution System) rate loading decisions in Sabre SynXis CRS. Used for channel mix analysis and cost-of-acquisition reporting. [ENUM-REF-CANDIDATE: direct|ota|gds|voice|group|wholesale|other — 7 candidates stripped; promote to reference product]',
    `commission_eligible` DECIMAL(18,2) COMMENT 'Indicates whether bookings in this segment are subject to travel agent or OTA commission payments. Direct corporate and government segments are typically non-commissionable; OTA and GDS segments carry commission obligations. Drives accounts payable commission processing in SAP S/4HANA.',
    `commission_rate_pct` DECIMAL(18,2) COMMENT 'Standard commission rate percentage applicable to bookings in this segment when commission_eligible is true. Expressed as a percentage of room revenue (e.g., 10.00 for 10%). Used for cost-of-acquisition analysis, OTA contract management, and CPOR (Cost Per Occupied Room) calculations. Confidential as it reflects contracted commercial terms.',
    `contribution_margin_tier` STRING COMMENT 'Classification of the segments typical contribution margin profile relative to other segments. Reflects net revenue after channel commissions, OTA fees, GDS fees, and loyalty redemption costs. Premium tiers (e.g., direct corporate) yield higher GOP (Gross Operating Profit) than low-margin OTA or wholesale segments. Used in GOPPAR analysis.. Valid values are `premium|standard|value|low_margin`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this market segment record was first created in the enterprise data lakehouse. Supports data lineage, audit trail, and record provenance tracking. Aligns with RECORD_AUDIT_CREATED requirement for MASTER_RESOURCE entities.',
    `crs_segment_code` STRING COMMENT 'The segment code as configured in Sabre SynXis CRS for central reservations and channel distribution. Used for rate plan distribution, availability controls, and channel-level segment reporting. Enables cross-system segment reconciliation.. Valid values are `^[A-Z0-9_]{1,20}$`',
    `demand_pattern` STRING COMMENT 'Classification of the temporal demand pattern exhibited by this market segment. Corporate transient segments typically show weekday concentration; leisure segments show weekend and seasonal peaks; event-driven segments spike around MICE (Meetings Incentives Conferences Exhibitions) events. Used in Infor EzRMS demand forecasting.. Valid values are `weekday|weekend|seasonal|year_round|event_driven`',
    `market_segment_description` STRING COMMENT 'Detailed narrative description of the market segment, including its defining characteristics, typical guest profile, booking behavior, and applicable rate strategies. Used for training, documentation, and business glossary alignment across revenue management, reservations, and sales teams.',
    `effective_from` DATE COMMENT 'Date from which this market segment definition becomes active and available for use in reservations, rate plans, and revenue reporting. Supports temporal validity management for segment taxonomy changes aligned with fiscal year or STR reporting period updates.',
    `effective_until` DATE COMMENT 'Date after which this market segment definition is no longer active. Null indicates an open-ended segment with no planned expiry. Supports segment lifecycle management and historical reporting continuity when segment taxonomies are revised.',
    `gdpr_data_subject_applicable` BOOLEAN COMMENT 'Indicates whether guest data associated with bookings in this market segment is subject to GDPR data subject rights (right to erasure, portability, access). Relevant for segments involving EU/EEA guests. Drives data retention and anonymization policies in the data lakehouse.',
    `gds_eligible` BOOLEAN COMMENT 'Indicates whether rates for this market segment are distributed through GDS (Global Distribution System) channels such as Amadeus, Sabre, and Travelport. Controls rate loading and availability display in Sabre SynXis CRS for GDS-connected travel agencies.',
    `group_block_eligible` BOOLEAN COMMENT 'Indicates whether this market segment supports group room block reservations. Group-eligible segments (e.g., MICE, sports groups, tour groups) require group block management in Oracle OPERA PMS and Delphi by Amadeus for BEO (Banquet Event Order) coordination.',
    `hierarchy_level` STRING COMMENT 'Numeric level of this segment within the market segment hierarchy. Level 1 represents top-level categories (e.g., Transient, Group); Level 2 represents sub-categories (e.g., Corporate, Leisure); Level 3 represents granular segments (e.g., Corporate Negotiated, Leisure OTA). Used for hierarchical roll-up in revenue reporting.',
    `is_internal_use_only` BOOLEAN COMMENT 'Indicates whether this market segment is for internal reporting and analytics purposes only and should not be exposed to guests, OTA partners, or external distribution channels. Internal segments (e.g., complimentary, house use, employee rate) are excluded from external rate distribution in Sabre SynXis CRS.',
    `loyalty_eligible` BOOLEAN COMMENT 'Indicates whether bookings under this market segment are eligible to earn loyalty program points and benefits. Wholesale, crew, and certain contracted segments may be excluded from loyalty accrual per program rules. Drives loyalty point calculation logic in Salesforce CRM loyalty management.',
    `market_segment_status` STRING COMMENT 'Current lifecycle status of the market segment record. Active segments are available for rate plan assignment, reservation coding, and revenue reporting. Inactive or deprecated segments are retained for historical analysis but excluded from new bookings. Aligns with MASTER_RESOURCE LIFECYCLE_STATUS requirement.. Valid values are `active|inactive|deprecated|pending_review`',
    `min_rate_override_allowed` BOOLEAN COMMENT 'Indicates whether revenue managers are permitted to override the minimum rate floor for this segment. Restricting overrides for high-value segments (e.g., LRA corporate) protects rate integrity. Configurable in IDeaS G3 RMS inventory controls and Oracle OPERA PMS rate management.',
    `negotiated_rate_required` BOOLEAN COMMENT 'Indicates whether bookings in this segment require a pre-negotiated rate agreement (e.g., corporate account rate, government per diem, airline crew contract). When true, a valid rate agreement must exist before reservations can be accepted at segment rates in Oracle OPERA PMS.',
    `no_show_propensity` DECIMAL(18,2) COMMENT 'Qualitative classification of the historical no-show rate tendency for this market segment. Distinct from cancellation propensity — no-shows occur without prior cancellation and have different revenue recovery implications. Used in overbooking model calibration within IDeaS G3 RMS.',
    `ota_eligible` BOOLEAN COMMENT 'Indicates whether rates for this market segment are distributed through OTA (Online Travel Agency) channels such as Expedia, Booking.com, and Hotels.com. Controls channel availability in Sabre SynXis CRS and impacts OTA commission cost tracking.',
    `pci_scope` BOOLEAN COMMENT 'Indicates whether payment card data associated with bookings in this segment falls within PCI DSS scope. Segments with direct card-present or card-not-present transactions require PCI-compliant data handling. Drives data masking and tokenization requirements in the lakehouse.',
    `pms_segment_code` STRING COMMENT 'The segment code as configured in Oracle OPERA PMS. Used for reservation coding, folio routing, and rate plan assignment at the property level. Enables reconciliation between the enterprise data lakehouse and the operational PMS source system.. Valid values are `^[A-Z0-9_]{1,20}$`',
    `price_sensitivity` DECIMAL(18,2) COMMENT 'Classification of the segments sensitivity to rate changes. Inelastic segments (e.g., airline crew, government contracted) book regardless of rate fluctuations. Highly elastic segments (e.g., leisure OTA) respond strongly to price changes. Drives DRR (Dynamic Rate Rule) configuration in IDeaS G3 RMS.',
    `rate_plan_category` STRING COMMENT 'Classification of the rate plan type typically associated with this segment. BAR (Best Available Rate) for transient leisure, negotiated for corporate accounts, LRA (Last Room Availability) for top-tier corporate, NRR (Non-Refundable Rate) for advance purchase segments. Drives rate loading in Oracle OPERA PMS and Sabre SynXis CRS. [ENUM-REF-CANDIDATE: bar|negotiated|lra|nrr|wholesale|package|complimentary — 7 candidates stripped; promote to reference product]',
    `record_status` STRING COMMENT '',
    `revenue_bucket` DECIMAL(18,2) COMMENT 'Primary revenue category associated with this market segment for TRevPAR (Total Revenue Per Available Room) and USALI departmental reporting. Rooms-focused segments contribute primarily to rooms revenue; MICE segments contribute across rooms, F&B (Food and Beverage), and events revenue buckets.',
    `rms_segment_code` STRING COMMENT 'The segment code as configured in IDeaS G3 RMS or Infor EzRMS. Used for demand forecasting, pricing optimization, and inventory control at the segment level. May differ from PMS segment code due to system-specific taxonomy requirements.. Valid values are `^[A-Z0-9_]{1,20}$`',
    `segment_category` STRING COMMENT 'High-level classification grouping the segment into a primary demand category. Drives pricing strategy, channel allocation, and revenue reporting roll-ups. Aligns with STR segment category definitions used in STAR Report benchmarking. [ENUM-REF-CANDIDATE: transient|group|contract|wholesale|ota|corporate|government|leisure|crew|airline — promote to reference product]',
    `segment_code` STRING COMMENT 'Short alphanumeric code uniquely identifying the market segment, used as the externally-known business identifier across Oracle OPERA PMS, IDeaS G3 RMS, Sabre SynXis CRS, and Infor EzRMS. Examples: CORP, TRANS, LEIS, OTA, GRP, GOVT, CREW. Aligns with STR segment code taxonomy for benchmarking and STAR Report mapping.. Valid values are `^[A-Z0-9_]{2,20}$`',
    `segment_name` STRING COMMENT 'Full descriptive name of the market segment as displayed in reporting, dashboards, and revenue management systems. Examples: Corporate Negotiated, Leisure Transient, Online Travel Agency, Government/Military, Group Meetings. Used as the IDENTITY_LABEL for this resource entity.',
    `segment_type` STRING COMMENT 'Secondary classification distinguishing whether the segment represents individual (FIT — Free Independent Traveler) bookings, group blocks, negotiated corporate accounts, wholesale/tour operator contracts, or consortia arrangements. Used in IDeaS G3 RMS for demand segmentation and pricing strategy.. Valid values are `individual|group|negotiated|wholesale|consortia`',
    `sort_order` STRING COMMENT 'Numeric value controlling the display sequence of market segments in reports, dashboards, and system configuration screens. Ensures consistent ordering in Oracle OPERA PMS segment lists, IDeaS G3 RMS segment configuration, and BI reporting tools.',
    `str_segment_code` STRING COMMENT 'The official STR (Smith Travel Research) segment code used for competitive benchmarking and STAR Report alignment. Enables mapping of internal segment definitions to the industry-standard STR taxonomy for RGI (Revenue Generation Index), MPI (Market Penetration Index), and ARI (Average Rate Index) calculations.. Valid values are `^[A-Z0-9]{2,10}$`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this market segment record was last modified. Tracks configuration changes to segment definitions, status updates, and taxonomy revisions. Essential for change data capture (CDC) in ETL pipelines feeding IDeaS G3 RMS and Infor EzRMS.',
    `usali_segment_code` STRING COMMENT 'The USALI (Uniform System of Accounts for the Lodging Industry) standardized segment code used for financial reporting and departmental P&L allocation. Ensures consistency in GOP (Gross Operating Profit), NOI (Net Operating Income), and EBITDA reporting across properties and for external financial audits under GAAP/IFRS.. Valid values are `^[A-Z0-9_]{2,15}$`',
    CONSTRAINT pk_market_segment PRIMARY KEY(`market_segment_id`)
) COMMENT 'Master classification of revenue market segments used for demand analysis, pricing strategy, and performance reporting. Defines segment code, segment name, segment category (transient, group, contract, wholesale, OTA, corporate, government, leisure, crew, airline), contribution margin profile, booking behavior characteristics, average lead time, and cancellation propensity. SSOT for market segment taxonomy aligned to STR segment definitions and used across revenue, reservation, and channel domains.';

CREATE OR REPLACE TABLE `vibe_travel_hospitality_v1`.`revenue`.`budget` (
    `budget_id` BIGINT COMMENT 'Unique surrogate identifier for each revenue budget record. Primary key for the revenue_budget data product in the Silver Layer lakehouse.',
    `fnb_outlet_id` BIGINT COMMENT 'Foreign key linking to fnb.fnb_outlet. Business justification: Revenue budgets include outlet-level F&B targets for total property budget planning. Required for USALI budget preparation, outlet performance targets, variance analysis, GOP planning at department le',
    `currency_id` BIGINT COMMENT 'Foreign key linking to property.currency. Business justification: All revenue_budget monetary targets (budgeted_room_revenue, budgeted_gop, target_adr) are currency-denominated. currency_code is denormalized; FK to currency enforces 3NF and enables multi-currency bu',
    `demand_forecast_id` BIGINT COMMENT 'Foreign key linking to revenue.demand_forecast. Business justification: Revenue budgets and strategic plans in hospitality are built on top of demand forecasts — the target_occupancy_rate, target_adr, and target_revpar in revenue_budget are derived from demand forecast pr',
    `hierarchy_id` BIGINT COMMENT 'Foreign key linking to property.hierarchy. Business justification: Revenue budgets are planned and approved at hierarchy node levels (brand, region, cluster). Linking revenue_budget to hierarchy enables hierarchical budget rollup for regional VP review, brand portfol',
    `market_segment_id` BIGINT COMMENT 'Reference to the market segment (e.g., transient leisure, transient corporate, group, wholesale, OTA) for which this budget is defined. Enables segment-level revenue planning and variance analysis.',
    `property_id` BIGINT COMMENT 'Reference to the property for which this revenue budget applies. Links to the property master record in the Property domain.',
    `revenue_center_id` BIGINT COMMENT 'Foreign key linking to fnb.revenue_center. Business justification: USALI standard hotel budgeting sets F&B targets at the revenue center level (e.g., restaurant vs. bar vs. banquet). revenue_budget has budgeted_fb_revenue but no revenue_center FK. This link supports ',
    `seasonal_calendar_id` BIGINT COMMENT 'Foreign key linking to property.seasonal_calendar. Business justification: Revenue budgets are planned by season (peak, shoulder, off-peak). Linking revenue_budget to seasonal_calendar enables season-based budget variance reporting, supports annual planning cycles aligned to',
    `approval_date` DATE COMMENT 'The date on which the revenue director formally approved this budget version. Marks the transition from draft to approved strategy status.',
    `budgeted_available_rooms` STRING COMMENT 'Total number of room-nights planned to be available for sale during the planning period (capacity baseline). Used as the denominator for RevPAR, TRevPAR, and GOPPAR calculations and STR STAR Report benchmarking.',
    `budgeted_cpor` DECIMAL(18,2) COMMENT 'Budgeted Cost Per Occupied Room (CPOR) in the propertys operating currency, representing the planned direct operating cost per occupied room night. Used for profitability planning and variance analysis against actuals.',
    `budgeted_events_revenue` DECIMAL(18,2) COMMENT 'Total budgeted revenue from Meetings, Incentives, Conferences, and Exhibitions (MICE) and event spaces for the planning period. Supports TRevPAR planning and event sales governance in Delphi by Amadeus.',
    `budgeted_fb_revenue` DECIMAL(18,2) COMMENT 'Total budgeted Food and Beverage (F&B) revenue in the propertys operating currency for the planning period. Supports TRevPAR planning and USALI departmental revenue reporting.',
    `budgeted_gop` DECIMAL(18,2) COMMENT 'Budgeted Gross Operating Profit (GOP) in the propertys operating currency for the planning period, per USALI departmental and undistributed expense structure. Used for GOPPAR derivation and owner NOI reporting.',
    `budgeted_occupied_rooms` STRING COMMENT 'Total number of room-nights planned to be occupied (sold) during the planning period. Derived from budgeted available rooms × target OCC, stored as a planning target for demand forecasting and group block management.',
    `budgeted_other_revenue` DECIMAL(18,2) COMMENT 'Total budgeted ancillary revenue (spa, parking, resort fees, retail, etc.) in the propertys operating currency for the planning period. Completes the TRevPAR revenue stack beyond rooms, F&B, and events.',
    `budgeted_room_revenue` DECIMAL(18,2) COMMENT 'Total budgeted room revenue (in operating currency) for the planning period and market segment. The primary monetary commitment in the revenue budget, used for variance analysis against actuals in the DOR and management reporting. Classified confidential as a strategic financial target.',
    `budgeted_total_revenue` DECIMAL(18,2) COMMENT 'Aggregate budgeted total revenue across all revenue streams (rooms + F&B + events + other) in the propertys operating currency for the planning period. The top-line financial commitment used in owner presentations and EBITDA planning.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this revenue budget record was first created in the lakehouse Silver Layer. Supports audit trail, data lineage, and SOX financial controls compliance.',
    `fiscal_period` STRING COMMENT 'The fiscal month or period number (1–12) within the fiscal year for monthly budget granularity. Supports period-level variance analysis in the DOR and management reporting.',
    `fiscal_year` STRING COMMENT 'The fiscal year to which this revenue budget belongs (e.g., 2025). Aligns with the propertys USALI-compliant financial reporting calendar and SAP S/4HANA GL fiscal periods.',
    `is_owner_approved` BOOLEAN COMMENT 'Indicates whether this budget has received formal approval from the property owner or ownership group (True = owner-approved; False = pending or not required). Relevant for managed properties where owner sign-off is contractually required.',
    `key_tactical_actions` STRING COMMENT 'Free-text description of the near-term tactical revenue actions planned for this budget period (e.g., BAR adjustments, LRA controls, OTA channel mix shifts, promotional rate activations). Captured from the revenue strategy narrative in IDeaS G3 RMS and Infor EzRMS.',
    `notes` STRING COMMENT 'Free-text field for additional context, assumptions, or commentary associated with this revenue budget record (e.g., macro-economic assumptions, renovation impact adjustments, force majeure notes). Supports management reporting and audit documentation.',
    `planning_horizon_type` STRING COMMENT 'Granularity of the planning horizon for this budget record: annual (full-year plan), quarterly (90-day rolling), monthly (period-level), or weekly (short-term tactical). Determines the reporting cadence for variance analysis.. Valid values are `annual|quarterly|monthly|weekly`',
    `planning_period_end_date` DATE COMMENT 'The last date of the planning horizon covered by this revenue budget (e.g., 2025-12-31 for an annual plan). Defines the effective end of the budget period.',
    `planning_period_start_date` DATE COMMENT 'The first date of the planning horizon covered by this revenue budget (e.g., 2025-01-01 for an annual plan). Defines the effective start of the budget period for variance tracking against actuals.',
    `property_segment` STRING COMMENT 'Brand/service tier of the property for which this budget applies: luxury, premium, select_service, or extended_stay. Enables cross-segment benchmarking and portfolio-level revenue governance.. Valid values are `luxury|premium|select_service|extended_stay`',
    `record_status` STRING COMMENT '',
    `reference_number` BIGINT COMMENT 'Externally-known alphanumeric identifier for this budget record, used in management reports, owner presentations, and cross-system references (e.g., SAP S/4HANA GL budget entries). Format: RB-{PropertyCode}-{Year}.',
    `strategic_initiatives` STRING COMMENT 'Free-text description of longer-horizon strategic revenue initiatives included in this budget (e.g., loyalty program rate strategy, new OTA partnership, dynamic pricing rule (DRR) rollout, group business development targets). Supports owner presentations and management reporting.',
    `strategy_status` STRING COMMENT 'Current lifecycle state of this revenue budget and strategy record. draft = under preparation; approved = signed off by revenue director; active = in-period execution; superseded = replaced by a newer version; archived = closed period record.. Valid values are `draft|approved|active|superseded|archived`',
    `strategy_type` STRING COMMENT 'Classifies the revenue strategy scope covered by this budget: transient (FIT/BAR-driven room revenue), group (MICE and group block revenue), total_revenue (TRevPAR-level all-revenue planning), food_and_beverage (F&B revenue plan), events (event/conference revenue), or other. [ENUM-REF-CANDIDATE: transient|group|total_revenue|food_and_beverage|events|other — promote to reference product]. Valid values are `transient|group|total_revenue|food_and_beverage|events|other`',
    `submission_date` DATE COMMENT 'The date on which this budget version was formally submitted for review and approval. Used for governance tracking and audit trail in owner presentations and management reporting.',
    `target_adr` DECIMAL(18,2) COMMENT 'Budgeted Average Daily Rate (ADR) in the propertys operating currency for the planning period. Represents the planned average revenue earned per occupied room per night. Core revenue KPI used in STR STAR Report, RGI, and MPI benchmarking.',
    `target_alos` DECIMAL(18,2) COMMENT 'Budgeted Average Length of Stay (ALOS) in nights for the planning period and market segment. Supports LOS-based pricing strategy, minimum stay restrictions, and demand pattern planning in IDeaS G3 RMS.',
    `target_ari` DECIMAL(18,2) COMMENT 'Budgeted Average Rate Index (ARI) target, representing the propertys planned ADR performance relative to its STR competitive set (property ADR / comp set ADR). Supports rate strategy and competitive positioning planning.',
    `target_goppar` DECIMAL(18,2) COMMENT 'Budgeted Gross Operating Profit Per Available Room (GOPPAR) in the propertys operating currency. Represents the profitability target per available room after operating expenses, used in owner presentations and GOP governance.',
    `target_mpi` DECIMAL(18,2) COMMENT 'Budgeted Market Penetration Index (MPI) target, representing the propertys planned occupancy performance relative to its STR competitive set (property OCC / comp set OCC). Supports competitive benchmarking strategy.',
    `target_occupancy_rate` DECIMAL(18,2) COMMENT 'Budgeted occupancy rate (OCC) expressed as a percentage (0.00–100.00) for the planning period. Represents the planned proportion of available rooms expected to be sold. Core KPI input for RevPAR calculation and STR STAR Report benchmarking.',
    `target_revpar` DECIMAL(18,2) COMMENT 'Budgeted Revenue Per Available Room (RevPAR) in the propertys operating currency for the planning period. Calculated as ADR × OCC but stored as a strategic target for direct comparison against actuals and STR competitive set benchmarks (RGI).',
    `target_rgi` DECIMAL(18,2) COMMENT 'Budgeted Revenue Generation Index (RGI) target, representing the propertys planned RevPAR performance relative to its STR competitive set (property RevPAR / comp set RevPAR). RGI > 1.0 indicates planned market share gain.',
    `target_trevpar` DECIMAL(18,2) COMMENT 'Budgeted Total Revenue Per Available Room (TRevPAR) in the propertys operating currency, encompassing all revenue streams (rooms, F&B, events, spa, parking, etc.) per available room. Supports total revenue strategy planning beyond rooms-only RevPAR.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this revenue budget record was most recently modified. Tracks version changes, reforecast updates, and approval workflow transitions for audit and governance purposes.',
    `version` STRING COMMENT 'Indicates the iteration of this budget record: original (initial annual plan), revised (mid-year adjustment), or reforecast (rolling forecast update). Supports version-controlled variance analysis in the Daily Operations Report (DOR) and management reporting.. Valid values are `original|revised|reforecast`',
    CONSTRAINT pk_budget PRIMARY KEY(`budget_id`)
) COMMENT 'Revenue planning, strategy, and budget records combining strategic revenue targets with financial budget commitments at the property and market segment level, aligned to USALI standards. Captures planning period, property, strategy type (transient, group, total revenue), target and budgeted ADR/occupancy/RevPAR/TRevPAR, budgeted room revenue, key tactical actions and strategic initiatives, budget version (original, revised, reforecast), strategy status (draft, approved, active), planning horizon, and approving revenue director. This is the SSOT for all revenue planning governance — both strategic direction and financial targets — used for variance analysis against actuals in the DOR, management reporting, owner presentations, and strategic revenue governance.';

CREATE OR REPLACE TABLE `vibe_travel_hospitality_v1`.`revenue`.`negotiated_rate` (
    `negotiated_rate_id` BIGINT COMMENT 'Unique surrogate identifier for the negotiated rate agreement record in the lakehouse Silver layer. Primary key for this entity.',
    `account_id` BIGINT COMMENT 'Foreign key linking to event.event_account. Business justification: Negotiated rates are contracted with specific event accounts (corporate, consortia, national accounts). Essential for contract rate management, event planner rate loading, and account-specific pricing',
    `accrual_rule_id` BIGINT COMMENT 'Foreign key linking to loyalty.accrual_rule. Business justification: Corporate negotiated rate contracts frequently specify custom points accrual rules (e.g., 1.5x earning on a preferred corporate rate). This FK links the negotiated rate to its contracted accrual rule,',
    `channel_contract_id` BIGINT COMMENT 'Foreign key linking to channel.channel_contract. Business justification: Negotiated rates are formalized under channel contracts (e.g., corporate account rates loaded under a GDS or OTA contract). Revenue and commercial teams need this FK for contract-rate reconciliation, ',
    `currency_id` BIGINT COMMENT 'Foreign key linking to property.currency. Business justification: Negotiated rate amounts are currency-denominated and must be loaded into GDS/CRS with correct currency context. currency_code is denormalized; FK to currency enforces 3NF and supports multi-currency c',
    `channel_id` BIGINT COMMENT 'Foreign key linking to channel.channel. Business justification: Corporate negotiated rates are loaded to specific channels (GDS with specific chain codes, OTA corporate programs, direct booking engines). Rate loading and distribution tracking requires knowing whic',
    `event_booking_id` BIGINT COMMENT 'Foreign key linking to event.event_booking. Business justification: MICE event-specific negotiated rates are a standard practice: a corporate account negotiates a bespoke rate for a specific annual conference. Revenue managers need to link the loaded rate directly to ',
    `fnb_outlet_id` BIGINT COMMENT 'Foreign key linking to fnb.fnb_outlet. Business justification: Corporate negotiated rates include outlet benefits (breakfast at specific outlet, lounge access). Required for contract fulfillment, benefit tracking, outlet revenue attribution, guest entitlement ver',
    `menu_id` BIGINT COMMENT 'Foreign key linking to fnb.menu. Business justification: Corporate negotiated rate contracts specify exact F&B menu inclusions (e.g., set breakfast menu, corporate dinner menu). revenue_negotiated_rate has included_fnb_outlet_id but no menu-level FK. Contra',
    `revenue_center_id` BIGINT COMMENT 'Foreign key linking to fnb.revenue_center. Business justification: Corporate negotiated rates with F&B inclusions are scoped to specific revenue centers (e.g., breakfast at main restaurant revenue center only, not room service). revenue_negotiated_rate has included_f',
    `market_segment_id` BIGINT COMMENT 'Foreign key linking to revenue.market_segment. Business justification: Negotiated rates are classified by market segment (e.g., Corporate, Wholesale). revenue_negotiated_rate has market_segment_code (STRING) which should be normalized to FK. N negotiated_rate records → 1',
    `tier_id` BIGINT COMMENT 'Foreign key linking to loyalty.tier. Business justification: Corporate negotiated rates often include tier-based eligibility or enhanced benefits. Business process: enforcing tier requirements for corporate rate access, common in negotiated contracts that offer',
    `promotion_id` BIGINT COMMENT 'Foreign key linking to loyalty.promotion. Business justification: Corporate negotiated rates are routinely bundled with loyalty promotions (e.g., a TMC accounts negotiated rate includes a bonus-points promotion for Q4). This FK supports corporate account loyalty bu',
    `property_id` BIGINT COMMENT 'Reference to the property for which this negotiated rate agreement applies. A single negotiated rate may be scoped to one property or replicated per property for multi-property contracts.',
    `redemption_rule_id` BIGINT COMMENT 'Foreign key linking to loyalty.redemption_rule. Business justification: Negotiated rate contracts specify whether and how points can be redeemed against that rate (e.g., points redemption blocked on lowest negotiated rates, or a special redemption multiplier applies). Thi',
    `revenue_rate_plan_id` BIGINT COMMENT 'Reference to the parent rate plan definition under which this negotiated rate is structured. Links to the rate plan master in Sabre SynXis CRS or Oracle OPERA PMS.',
    `room_type_id` BIGINT COMMENT 'Reference to the specific room type to which this negotiated rate applies. Null if the rate applies to all room types under the agreement.',
    `advance_booking_days` STRING COMMENT 'Minimum number of days in advance a reservation must be made to qualify for this negotiated rate. Zero indicates same-day booking is permitted.',
    `amount` DECIMAL(18,2) COMMENT 'The contracted nightly room rate (Average Daily Rate) agreed upon for this account. Represents the fixed or base rate per room per night in the specified currency. Core pricing field for revenue management and contract compliance.',
    `approval_status` STRING COMMENT 'Approval workflow status for this negotiated rate agreement. Rates must be approved by revenue management leadership before loading into CRS/GDS channels.. Valid values are `approved|pending_approval|rejected|under_review`',
    `approved_by` STRING COMMENT 'Name or employee identifier of the revenue management leader or director who approved this negotiated rate agreement for distribution.',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when this negotiated rate agreement received final approval for loading and distribution.',
    `blackout_dates` STRING COMMENT 'Comma-separated list or date range expressions representing dates on which this negotiated rate is not available (e.g., peak demand periods, holidays, special events). Stored as a structured string; detailed blackout records are managed in the rate_restriction product.',
    `breakfast_included` BOOLEAN COMMENT 'Indicates whether breakfast is included in the negotiated rate. Affects F&B (Food and Beverage) revenue allocation and rate value proposition reporting.',
    `commission_pct` DECIMAL(18,2) COMMENT 'Commission percentage payable to the TMC, travel agency, or consortia for reservations booked under this negotiated rate. Expressed as a percentage of the negotiated rate amount.',
    `committed_room_nights` STRING COMMENT 'Total number of room nights the account has committed to book under this negotiated rate agreement for the contract period. Basis for volume discount qualification and contract performance tracking.',
    `consortia_code` STRING COMMENT 'Identifier for the travel consortia (e.g., Virtuoso, Signature, Ensemble, Internova) under which this negotiated rate is offered. Null for direct corporate accounts not affiliated with a consortia.',
    `contract_end_date` DATE COMMENT 'The date on which the negotiated rate agreement expires and the rate is no longer available for booking. Null for open-ended agreements. Aligns with the MASTER_AGREEMENT EFFECTIVE_UNTIL category.',
    `contract_reference_number` BIGINT COMMENT 'External contract or agreement reference number assigned by the account, TMC, or legal department. Used for contract management, audit, and dispute resolution.',
    `contract_start_date` DATE COMMENT 'The date from which the negotiated rate agreement becomes contractually binding and the rate is available for booking. Aligns with the MASTER_AGREEMENT EFFECTIVE_FROM category.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this negotiated rate record was first created in the source system. Supports audit trail, data lineage, and GDPR/CCPA data lifecycle management.',
    `gds_chain_code` STRING COMMENT 'Two-letter GDS chain code used to identify the hotel brand/chain in Sabre, Amadeus, Galileo, and Worldspan for rate loading and distribution of this negotiated rate.. Valid values are `^[A-Z]{2}$`',
    `iata_number` BIGINT COMMENT 'IATA-assigned numeric identifier for the Travel Management Company (TMC) or travel agency associated with this negotiated rate. Used for commission tracking and GDS rate access validation.',
    `is_lra` BOOLEAN COMMENT 'Indicates whether this negotiated rate carries a Last Room Availability (LRA) obligation, requiring the property to honor the contracted rate as long as any room of the applicable type remains available, regardless of demand or yield management controls.',
    `is_non_refundable` BOOLEAN COMMENT 'Indicates whether reservations booked under this negotiated rate are non-refundable (NRR). Affects cancellation policy enforcement and revenue recognition timing.',
    `max_los` STRING COMMENT 'Maximum number of consecutive nights allowed per reservation under this negotiated rate. Null if no upper limit is imposed.',
    `min_los` STRING COMMENT 'Minimum number of consecutive nights required per reservation to qualify for this negotiated rate. Enforced at booking in Sabre SynXis CRS and Oracle OPERA PMS.',
    `min_night_commitment` STRING COMMENT 'Minimum number of room nights the account is contractually committed to consume during the contract period. Used for volume tracking and contract compliance reporting.',
    `negotiation_owner` STRING COMMENT 'Name or employee identifier of the revenue manager or sales manager responsible for negotiating and managing this rate agreement. Used for accountability and performance tracking.',
    `rate_bar_variance_pct` DECIMAL(18,2) COMMENT 'The percentage discount or premium of this negotiated rate relative to the Best Available Rate (BAR) at time of contract negotiation. Used by revenue management to assess rate competitiveness and yield impact.',
    `rate_code` STRING COMMENT 'Alphanumeric rate code used to identify and load this negotiated rate in Sabre SynXis CRS and Oracle OPERA PMS. This is the externally-known business identifier referenced in GDS/CRS rate loading and reservation transactions.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `rate_includes_tax` DECIMAL(18,2) COMMENT 'Indicates whether the negotiated rate amount is inclusive of applicable taxes. Critical for revenue recognition, financial reporting, and guest billing accuracy.',
    `rate_loaded_timestamp` TIMESTAMP COMMENT 'Date and time when the negotiated rate was successfully loaded into Sabre SynXis CRS and/or Oracle OPERA PMS for distribution. Null if loading has not yet occurred.',
    `rate_loading_status` STRING COMMENT 'Current status of the rate loading process in Sabre SynXis CRS and Oracle OPERA PMS. Indicates whether the negotiated rate has been successfully distributed to all applicable booking channels.. Valid values are `loaded|pending|failed|not_loaded|deactivated`',
    `rate_name` STRING COMMENT 'Human-readable name describing the negotiated rate agreement, typically referencing the account or program name (e.g., Acme Corp 2025 Corporate Rate). Used in reporting and rate management dashboards.',
    `rate_status` STRING COMMENT 'Current lifecycle status of the negotiated rate agreement. Controls whether the rate is bookable and distributed through CRS/GDS channels.. Valid values are `active|inactive|pending|suspended|expired|draft`',
    `rate_type` STRING COMMENT 'Classification of the pricing structure for this negotiated rate. Fixed rates are static for the contract period; dynamic rates may fluctuate within agreed bounds; tiered rates vary by volume; per diem rates are government-mandated ceiling rates.. Valid values are `fixed|dynamic|tiered|per_diem`',
    `record_status` STRING COMMENT '',
    `source_system_rate_reference` DECIMAL(18,2) COMMENT 'Native identifier of this negotiated rate record in the originating operational system (Oracle OPERA PMS, Sabre SynXis CRS, or Salesforce CRM). Enables traceability and reconciliation between the lakehouse and source systems.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this negotiated rate record was last modified in the source system. Supports change tracking, audit compliance, and incremental ETL processing.',
    CONSTRAINT pk_negotiated_rate PRIMARY KEY(`negotiated_rate_id`)
) COMMENT 'Corporate and wholesale negotiated rate agreements defining contracted pricing for specific accounts, travel management companies (TMCs), and consortia. Captures account identifier, rate code, negotiated rate amount, LRA (Last Room Availability) obligation, blackout dates, minimum night commitment, contract period, and rate loading status in Sabre SynXis CRS and Oracle OPERA PMS. Distinct from public rate plans — these are account-specific contracted rates.';

CREATE OR REPLACE TABLE `vibe_travel_hospitality_v1`.`revenue`.`restriction_application` (
    `restriction_application_id` BIGINT COMMENT 'Primary key for the restriction_application association',
    `rate_availability_id` BIGINT COMMENT 'Foreign key linking to the specific daily rate and availability snapshot to which this restriction is applied.',
    `rate_restriction_id` BIGINT COMMENT 'Foreign key linking to the rate restriction rule being applied to the availability record.',
    `advance_purchase_days` STRING COMMENT 'Minimum number of days in advance a booking must be made to qualify for this rate plan on the snapshot date (e.g., 7-day advance purchase, 21-day advance purchase for NRR rates). A key rate restriction parameter managed in IDeaS G3 RMS and Sabre SynXis CRS. [Moved from rate_availability: Advance purchase requirement is a restriction rule attribute defined on rate_restriction. Its presence on rate_availability is a denormalized snapshot of the active restriction. The restriction_application association provides the proper operational link between the restriction definition and the availability record.]',
    `applied_timestamp` TIMESTAMP COMMENT 'The date and time when this specific restriction was activated and applied to the linked rate availability record. Sourced from detection phase relationship data.',
    `closed_to_arrival` BOOLEAN COMMENT 'Indicates whether new arrivals are blocked on the snapshot date for this room type and rate plan. When True, guests cannot check in on this date but may continue an existing stay through it. A yield management restriction used to optimize multi-night booking patterns. [Moved from rate_availability: CTA is a restriction type managed in rate_restriction. Its presence on rate_availability is a denormalized snapshot. The restriction_application association captures which specific CTA restriction record is applied to which availability record, with its own status and override state.]',
    `closed_to_departure` BOOLEAN COMMENT 'Indicates whether departures are blocked on the snapshot date for this room type and rate plan. When True, guests cannot check out on this date, forcing stays to extend through it. Used in conjunction with CTA restrictions to shape booking patterns during peak periods. [Moved from rate_availability: CTD is a restriction type managed in rate_restriction. Same reasoning as closed_to_arrival — the denormalized boolean on rate_availability should be derived from the active restriction_application records rather than stored redundantly.]',
    `distribution_status` STRING COMMENT 'Indicates whether this specific restriction application has been successfully distributed to connected channel systems (GDS, OTA, CRS) for this availability record. Distinct from the restriction-level distribution_status on rate_restriction. Sourced from detection phase relationship data.',
    `los_maximum` STRING COMMENT 'Maximum number of nights permitted under this rate plan for the snapshot date. Used to prevent long-stay bookings at promotional rates during high-demand periods. Managed in IDeaS G3 RMS as an upper LOS (Length of Stay) restriction. [Moved from rate_availability: Same reasoning as los_minimum — maximum LOS is a restriction rule attribute. Its denormalization on rate_availability collapses multiple simultaneous restriction applications into a single value, losing the operational detail that restriction_application captures.]',
    `los_minimum` STRING COMMENT 'Minimum number of nights a guest must stay to qualify for this rate plan on the snapshot date. A key yield optimization restriction managed in IDeaS G3 RMS. LOS (Length of Stay) restrictions are used to maximize revenue during high-demand periods by requiring multi-night commitments. [Moved from rate_availability: Minimum LOS is a restriction attribute that belongs to the restriction_application pairing. Its presence on rate_availability represents a denormalized snapshot of the currently active restriction. When multiple restrictions with different LOS rules apply simultaneously, a single los_minimum on rate_availability cannot represent the full picture. The authoritative value lives on rate_restriction and the effective application state lives on restriction_application.]',
    `override_allowed` BOOLEAN COMMENT 'Indicates whether a revenue manager or authorized staff member is permitted to manually override this specific restriction application for the linked availability record. Sourced from detection phase relationship data.',
    `priority_rank` STRING COMMENT 'Numeric priority rank used to resolve conflicts when multiple restrictions are simultaneously applied to the same rate availability record. Determines which restriction takes precedence when rules conflict. Sourced from detection phase relationship data.',
    `restriction_status` STRING COMMENT 'Current operational status of this specific restriction-to-availability pairing. Tracks whether the restriction is actively enforced, has expired, or has been overridden for this availability record. Sourced from detection phase relationship data.',
    CONSTRAINT pk_restriction_application PRIMARY KEY(`restriction_application_id`)
) COMMENT 'This association product represents the operational application of a rate restriction to a specific rate availability record in the revenue management system. It captures the active state of each restriction-to-availability pairing as managed in IDeaS G3 RMS and distributed via Sabre SynXis CRS. Each record links one rate_availability snapshot to one rate_restriction rule with attributes that exist only in the context of this specific application — including activation timestamp, distribution status, priority rank for conflict resolution, and override authorization state.. Existence Justification: In IDeaS G3 RMS and Sabre SynXis CRS, revenue managers explicitly apply multiple rate restrictions (min LOS, CTA, CTD, advance purchase, blackout) simultaneously to a single rate availability record, and a single restriction definition (e.g., a 2-night minimum LOS rule) covers many availability records across its date range, room type scope, and rate plan scope. This is an actively managed operational concept — revenue managers create, activate, override, and expire these restriction-to-availability pairings as a core yield optimization workflow. The relationship is a first-class operational entity called restriction_application in RMS terminology, carrying its own status, priority, and override metadata.';

